// ─── DETERMINISTIC DETECTION ENGINE (Phase 1 — the audit spine) ──────────────
// The platform's findings used to be GENERATED by the LLM from a prompt that
// merely *described* detection methods. That made findings non-reproducible
// (no seed/temperature), ungrounded (no tie to source rows), and capped at the
// 5,000 rows that fit in a prompt — contradicting the "100% population" claim.
//
// This engine replaces that for live data: it runs RULE-BASED detection in pure
// JavaScript over the ENTIRE uploaded population, using the same thresholds the
// user configures in Rule Parameters (the threshold registry — single source of
// truth). It is the system of record for WHETHER a finding exists and its
// severity. The LLM is demoted to writing narrative on top (see narration path).
//
// Properties that make it audit-defensible:
//   • Reproducible — pure function of (rows, thresholds, asOf). Same input →
//     byte-identical findings + a stable content hash.
//   • Grounded — every finding carries `evidence` with the source-row key, the
//     exact field values that triggered it, and the rule expression, so an
//     auditor can re-perform it. Nothing is asserted that isn't in the data.
//   • Full population — iterates every row; no sampling, no row cap.
//
// Adding/▶ tuning a rule: edit the agent's entry in DETECTORS below. Thresholds
// come from the registry (frontend/src/data/thresholdRegistry.js) via getDefaults.

import { getDefaults } from '../data/thresholdRegistry.js';
import { chiSquareSf, benjaminiHochberg, median, mad, modifiedZ, normalSf, binomialSf, haversineKm } from './statistics.js';
import { cityCoords } from '../data/cityGeo.js';

export const ENGINE_VERSION = '1.1.0';

// False-discovery-rate level for the multiple-testing control (S1). 0.05 is the
// conventional default; it's a methodological constant, overridable per run via
// ctx.fdrQ. It bounds the expected proportion of false positives among the
// engine's STATISTICAL findings (those carrying a p-value); rule-based
// regulatory facts (floor breaches, SoD, single-obligor) never participate.
export const DEFAULT_FDR_Q = 0.05;

// ─── value coercion helpers (CSV cells arrive as strings) ────────────────────
export function num(v) {
  if (typeof v === 'number') return Number.isFinite(v) ? v : null;
  if (v == null) return null;
  const n = parseFloat(String(v).replace(/[, ]/g, ''));
  return Number.isFinite(n) ? n : null;
}
function bool(v) {
  if (v === true) return true;
  if (v === false || v == null) return false;
  return /^(true|t|yes|y|1)$/i.test(String(v).trim());
}
function str(v) { return v == null ? '' : String(v).trim(); }

// Whole days between an ISO-ish date string and an as-of date (ms). Deterministic
// because asOf is supplied by the caller, never Date.now() inside the engine.
function daysSince(dateStr, asOfMs) {
  if (!dateStr || asOfMs == null) return null;
  const t = Date.parse(String(dateStr));
  if (!Number.isFinite(t)) return null;
  return Math.floor((asOfMs - t) / 86_400_000);
}
function daysUntil(dateStr, asOfMs) {
  const d = daysSince(dateStr, asOfMs);
  return d == null ? null : -d;
}

const SEV_RANK = { critical: 3, high: 2, medium: 1, low: 0 };
function worse(a, b) { return (SEV_RANK[b] ?? -1) > (SEV_RANK[a] ?? -1) ? b : a; }

// Deterministic, dependency-free content hash (FNV-1a, 32-bit hex). Used to
// stamp a run so two runs over identical data can be proven identical.
export function stableHash(value) {
  const json = stableStringify(value);
  let h = 0x811c9dc5;
  for (let i = 0; i < json.length; i++) {
    h ^= json.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}
function stableStringify(v) {
  if (v === null || typeof v !== 'object') return JSON.stringify(v);
  if (Array.isArray(v)) return '[' + v.map(stableStringify).join(',') + ']';
  return '{' + Object.keys(v).sort().map(k => JSON.stringify(k) + ':' + stableStringify(v[k])).join(',') + '}';
}

// Confidence from how far past the threshold the worst signal sits (0.50–0.99).
// A reproducible MARGIN score — honest, but not a probability. Used as the
// fallback for pure rule findings that have no underlying distribution.
function marginConfidence(triggeredBy) {
  let best = 0;
  for (const t of triggeredBy || []) {
    if (typeof t.value !== 'number' || typeof t.threshold !== 'number' || !t.threshold) continue;
    const ratio = t.op === '<=' || t.op === '<'
      ? (t.threshold - t.value) / Math.abs(t.threshold)
      : (t.value - t.threshold) / Math.abs(t.threshold);
    if (ratio > best) best = ratio;
  }
  return Math.max(0.5, Math.min(0.99, 0.6 + best)); // 0% over → 0.60, ≥39% over → 0.99
}

// Confidence as a real PROBABILITY where the finding carries a statistical test:
// confidence = 1 − p (the significance of the result). Otherwise fall back to the
// margin score and label it honestly. Returns { value, basis }.
//   basis 'p-value' → value is a genuine tail-probability significance
//   basis 'margin'  → value is a reproducible distance-past-threshold score
function statisticalConfidence(res) {
  const stat = res && res.statistic;
  if (stat && typeof stat.p === 'number' && Number.isFinite(stat.p)) {
    return { value: Math.max(0.5, Math.min(0.9999, 1 - stat.p)), basis: 'p-value' };
  }
  return { value: marginConfidence(res && res.triggeredBy), basis: 'margin' };
}

// Default peer-relative outlier cutoff (modified-z). 3.5 is the published
// Iglewicz–Hoaglin rule of thumb; per-agent registry knobs can tighten it.
export const DEFAULT_OUTLIER_Z = 3.5;

// PEER-RELATIVE ROBUST-OUTLIER TEST (S2). Is `value` extreme vs `peerValues`,
// judged by the robust modified-z (median + MAD, so a few outliers don't hide
// each other)? Returns a grounded triggeredBy item + a `statistic` carrying a
// real one-sided p-value (so confidence = 1−p and the finding is FDR-controlled),
// or null when not an outlier. The fixed registry threshold is preserved as a
// HARD FLOOR by the CALLER — this only ADDS peer-relative outliers on top; it
// never removes a floor-breach flag ("tighten/extend, never loosen"). Needs
// ≥ minN peers for a stable baseline, else returns null (caller keeps the floor).
function robustOutlier(value, peerValues, { zCut = DEFAULT_OUTLIER_Z, minN = 30, field, label, upper = true, twoSided = false } = {}) {
  if (!Number.isFinite(value)) return null;
  const peers = (peerValues || []).filter(v => typeof v === 'number' && Number.isFinite(v));
  if (peers.length < minN) return null;
  const med = median(peers), m = mad(peers);
  if (med == null || m == null || m <= 0) return null; // no dispersion → can't assess
  const z = modifiedZ(value, med, m);
  const extreme = twoSided ? Math.abs(z) >= zCut : (upper ? z >= zCut : z <= -zCut);
  if (!extreme) return null;
  const hi = twoSided ? z >= 0 : upper;
  const p = twoSided ? Math.min(1, 2 * normalSf(Math.abs(z))) : (upper ? normalSf(z) : normalSf(-z));
  // Effective cutoff in original units (value at which |z| = zCut): med ± zCut·MAD/0.6745.
  const effCut = hi ? med + (zCut * m) / 0.6745 : med - (zCut * m) / 0.6745;
  return {
    z,
    tb: {
      field,
      value: Math.round(value * 100) / 100,
      op: hi ? '>=' : '<=',
      threshold: Math.round(effCut * 100) / 100,
      rule: label || `${field}: robust-z outlier vs peer group (z=${z.toFixed(1)}, peer median ${Math.round(med * 100) / 100})`,
    },
    statistic: { test: 'robust-z', value: Math.round(z * 100) / 100, p, peerMedian: Math.round(med * 100) / 100, mad: Math.round(m * 100) / 100 },
  };
}

// Same as robustOutlier but against PRE-COMPUTED peer stats (ctx.peerStats[field]
// = { median, mad }), for per-row detectors that opt in via spec.peerStats.
function peerOutlier(value, ps, { zCut = DEFAULT_OUTLIER_Z, minN = 30, field, label, upper = true } = {}) {
  if (!ps || ps.mad == null || ps.mad <= 0 || !Number.isFinite(value)) return null;
  if (ps.n != null && ps.n < minN) return null; // too small a baseline → caller keeps the fixed floor
  const z = modifiedZ(value, ps.median, ps.mad);
  if (upper ? z < zCut : z > -zCut) return null;
  const p = upper ? normalSf(z) : normalSf(-z);
  const effCut = upper ? ps.median + (zCut * ps.mad) / 0.6745 : ps.median - (zCut * ps.mad) / 0.6745;
  return {
    z,
    tb: { field, value: Math.round(value * 100) / 100, op: upper ? '>=' : '<=', threshold: Math.round(effCut * 100) / 100, rule: label || `${field}: robust-z outlier vs population (z=${z.toFixed(1)}, median ${Math.round(ps.median * 100) / 100})` },
    statistic: { test: 'robust-z', value: Math.round(z * 100) / 100, p, peerMedian: Math.round(ps.median * 100) / 100, mad: Math.round(ps.mad * 100) / 100 },
  };
}

// FALSE-DISCOVERY-RATE post-pass (Benjamini–Hochberg). Operates ONLY on findings
// that carry a statistical p-value (evidence.statistic.p) — i.e. anomaly
// hypothesis tests, never rule-based regulatory facts. With many statistical
// tests over a large population some will look significant by chance; BH bounds
// the expected false-positive proportion at q. A finding that fails FDR is NOT
// dropped (audit honesty) — it is demoted to an advisory 'low' tier and tagged,
// so it stays visible but no longer inflates the headline severity counts.
// Mutates the findings in place. Returns { tested, discoveries, q }.
function applyFdr(findings, q) {
  const idx = [];
  for (let i = 0; i < findings.length; i++) {
    const p = findings[i]?.evidence?.statistic?.p;
    if (typeof p === 'number' && Number.isFinite(p)) idx.push(i);
  }
  if (idx.length === 0) return { tested: 0, discoveries: 0, q };
  const { significant, pAdjusted } = benjaminiHochberg(idx.map(i => findings[i].evidence.statistic.p), q);
  let discoveries = 0;
  idx.forEach((fi, k) => {
    const f = findings[fi];
    const sig = significant[k];
    f.fdr = { q, significant: sig, pAdjusted: Math.round(pAdjusted[k] * 1e6) / 1e6 };
    if (sig) { discoveries++; return; }
    // Demote to advisory — keep the evidence, drop the severity weight.
    f.belowFdr = true;
    f.originalSeverity = f.severity;
    f.severity = 'low';
    f.finding = `${f.finding} [advisory: below the FDR q=${q} significance threshold after multiple-testing correction]`;
  });
  return { tested: idx.length, discoveries, q };
}

// Benford digit-distribution test (Nigrini). `digits` = 1 (first-digit, df=8) or
// 2 (first-two-digit, 10–99, df=88). Returns { chi2, df, p, n, leadDigits } or
// null when too few amounts. A material χ² (small p) signals fabricated or
// manipulated amounts. Pure function of the amount column → reproducible.
function benfordTest(amounts, digits = 1) {
  const vals = (amounts || []).filter(a => typeof a === 'number' && Number.isFinite(a) && a > 0);
  const minN = digits === 2 ? 300 : 50;
  if (vals.length < minN) return null;
  const lead = (a) => {
    const s = String(a).replace(/[^0-9]/g, '').replace(/^0+/, '');
    if (digits === 2) return s.length >= 2 ? parseInt(s.slice(0, 2), 10) : null;
    return s.length >= 1 ? parseInt(s[0], 10) : null;
  };
  const lo = digits === 2 ? 10 : 1, hi = digits === 2 ? 99 : 9;
  const counts = {};
  let n = 0;
  for (const a of vals) { const d = lead(a); if (d != null && d >= lo && d <= hi) { counts[d] = (counts[d] || 0) + 1; n++; } }
  if (n < minN) return null;
  let chi2 = 0;
  // Per-digit observed vs Benford-expected proportions — returned so the UI can
  // chart the distribution (grounded: the chart IS the test's input).
  const dist = [];
  for (let d = lo; d <= hi; d++) {
    const exp = n * Math.log10(1 + 1 / d); if (exp > 0) chi2 += (((counts[d] || 0) - exp) ** 2) / exp;
    dist.push({ digit: d, observed: Math.round(((counts[d] || 0) / n) * 1e4) / 1e4, expected: Math.round(Math.log10(1 + 1 / d) * 1e4) / 1e4 });
  }
  chi2 = Math.round(chi2 * 100) / 100;
  const df = hi - lo;
  return { chi2, df, p: chiSquareSf(chi2, df), n, digits, dist };
}

// Hour-of-day from an ISO/space timestamp WITHOUT Date() (timezone-independent,
// so the engine stays deterministic across machines).
function hourOf(ts) {
  const m = String(ts || '').match(/[T ](\d{2}):/);
  return m ? parseInt(m[1], 10) : null;
}

// Per-staff behavioural composite — shared by the Insider and (consolidated)
// Staff/Access agents. Groups rows by staff_id and scores SoD breaches
// (self-initiated AND self-approved), override concentration, and off-hours
// activity into a transparent weighted composite vs the risk_score_flag cutoff.
// `accessByStaff` (optional) maps staff/user id → entitlement-layer flags from
// the Access Rights feed. When a behaviourally-flagged staff member ALSO has an
// entitlement-layer issue (toxic combination, dormant-privileged, SoD conflict),
// that cross-layer convergence escalates the finding to critical — the core of
// the consolidated Staff/Access agent.
function staffComposite(rows, t, accessByStaff = null, opts = {}) {
  const cutoff = t.risk_score_flag ?? t.composite_flag ?? 0.70;
  const offCut = (t.off_hours_staff_pct ?? t.off_hours_pct ?? 15) / 100;
  const byStaff = {};
  rows.forEach((r, i) => { const s = str(r.staff_id) || str(r.user_id); if (s) (byStaff[s] ||= []).push({ r, i }); });
  const out = [];
  for (const [staff, items] of Object.entries(byStaff)) {
    const n = items.length; if (!n) continue;
    let sod = 0, override = 0, offHours = 0;
    for (const { r } of items) {
      if (bool(r.initiator_flag) && bool(r.approver_flag)) sod++;
      if (bool(r.override_flag)) override++;
      const hh = hourOf(r.timestamp);
      if (hh != null && (hh < 6 || hh >= 21)) offHours++;
    }
    const overrideRate = override / n, offRate = offHours / n;
    // Weighted composite (mirrors the documented insider methodology weights).
    const composite = Math.min(1, (sod > 0 ? 0.4 : 0) + overrideRate * 0.35 + offRate * 0.25);
    if (composite < cutoff) continue;
    const tb = [];
    if (sod > 0) tb.push({ field: 'sod_breaches', value: sod, op: '>=', threshold: 1, rule: 'Self-initiated AND self-approved transactions (SoD breach)' });
    if (overrideRate >= 0.5) tb.push({ field: 'override_rate_pct', value: Math.round(overrideRate * 100), op: '>=', threshold: 50, rule: 'Override concentration by one staff member' });
    if (offRate >= offCut) tb.push({ field: 'off_hours_pct', value: Math.round(offRate * 100), op: '>=', threshold: Math.round(offCut * 100), rule: 'Off-hours activity share' });
    tb.push({ field: 'composite_score', value: Math.round(composite * 100) / 100, op: '>=', threshold: Math.round(cutoff * 100) / 100, rule: 'Insider composite risk score' });
    const critCut = opts.critCut ?? (cutoff + 0.15);
    const boost = opts.multiLayerBoost ?? 0;
    let sev = composite >= critCut ? 'critical' : 'high';
    // Cross-layer convergence: same subject also flagged at the entitlement layer.
    // The configured multi-layer boost adds to the composite; if that crosses the
    // critical cutoff the finding escalates to critical.
    let crossLayer = null;
    const acc = accessByStaff && accessByStaff[staff];
    if (acc) {
      const issues = [];
      if (bool(acc.toxic_combination_code) || str(acc.toxic_combination_code)) issues.push('toxic entitlement combination');
      if (bool(acc.sod_conflict_flag)) issues.push('SoD entitlement conflict');
      if (bool(acc.dormant_flag) && /admin|dba|privil/i.test(str(acc.privilege_level) + str(acc.role))) issues.push('dormant privileged account');
      if (issues.length) { crossLayer = issues.join(', '); tb.push({ field: 'cross_layer', value: issues.length, op: '>=', threshold: 1, rule: `Entitlement-layer corroboration: ${crossLayer}` }); if ((composite + boost) >= critCut) sev = 'critical'; }
    }
    out.push({
      row: { staff_id: staff, ...items[0].r, composite_score: composite },
      rowIndex: items[0].i,
      severity: sev,
      finding: `Staff ${staff} (${str(items[0].r.role) || 'role n/a'}): insider composite ${composite.toFixed(2)} over ${n} actions — ${tb.filter(x => x.field !== 'composite_score').map(x => x.rule).join('; ') || 'elevated behavioural pattern'}${crossLayer ? ` — CROSS-LAYER: also ${crossLayer} at the entitlement layer` : ''}.`,
      recommended_action: crossLayer
        ? 'Cross-layer convergence — treat as priority: independent review, preserve access logs, suspend access pending investigation.'
        : 'Independent review of this staff member’s approvals; preserve access logs; consider access suspension pending investigation.',
      triggeredBy: tb,
      extra: { composite_score: composite, sod_breaches: sod, actions: n, cross_layer: crossLayer },
    });
  }
  return out;
}

// ─── PER-AGENT DETECTORS ─────────────────────────────────────────────────────
// Each detector: { key, listKey, summaryKey, exposureField?, domains?, label,
//   detect(row, t, ctx) → null | { severity, finding, recommended_action?, triggeredBy[] } }
// `t` is the agent's resolved thresholds (registry defaults merged with overrides).
// `triggeredBy` items: { field, value, op, threshold, rule } — the audit evidence.

const D = {
  // ── CREDIT: SLFRS 9 staging — predicted stage from raw signals vs assigned ──
  credit: {
    key: 'loan_id', listKey: 'flagged_loans', summaryKey: 'portfolio_summary',
    exposureField: 'exposure_lkr', domains: ['audit'],
    label: r => `Loan ${str(r.loan_id) || '?'}`,
    detect(r, t) {
      const dpd = num(r.dpd_days), coll = num(r.collateral_ratio), rc = num(r.restructure_count);
      const assigned = num(r.assigned_stage);
      if (assigned == null) return null;
      let predicted = 1; const tb = [];
      const dpd3 = t.dpd_stage3 ?? 90, dpd2 = t.dpd_stage2 ?? 30;
      const c3 = t.collateral_stage3 ?? 0.40, c2 = t.collateral_stage2 ?? 0.70, rs3 = t.restructure_stage3 ?? 2;
      if (dpd != null && dpd >= dpd3) { predicted = 3; tb.push({ field: 'dpd_days', value: dpd, op: '>=', threshold: dpd3, rule: 'SLFRS 9 90-day past-due presumption → Stage 3' }); }
      else if (dpd != null && dpd >= dpd2) { predicted = Math.max(predicted, 2); tb.push({ field: 'dpd_days', value: dpd, op: '>=', threshold: dpd2, rule: 'DPD ≥ Stage 2 trigger' }); }
      if (coll != null && coll <= c3) { predicted = 3; tb.push({ field: 'collateral_ratio', value: coll, op: '<=', threshold: c3, rule: 'Collateral ratio at/below Stage 3 floor' }); }
      else if (coll != null && coll <= c2) { predicted = Math.max(predicted, 2); tb.push({ field: 'collateral_ratio', value: coll, op: '<=', threshold: c2, rule: 'Collateral ratio at/below Stage 2 floor' }); }
      if (rc != null && rc >= rs3) { predicted = Math.max(predicted, 3); tb.push({ field: 'restructure_count', value: rc, op: '>=', threshold: rs3, rule: 'Repeated restructuring → Stage 3' }); }
      if (predicted <= assigned || tb.length === 0) return null; // not understated
      return {
        severity: predicted === 3 ? 'critical' : 'high',
        finding: `Loan ${str(r.loan_id)} is classified Stage ${assigned} but its signals imply Stage ${predicted} (understated provisioning).`,
        recommended_action: `Reclassify to Stage ${predicted} and recompute ECL; document or correct the staging exception.`,
        triggeredBy: tb, extra: { assigned_stage: assigned, predicted_stage: predicted },
      };
    },
    // Population passes: (a) per-sector Stage-3 NPL concentration; (b) VINTAGE
    // cohort analysis — Stage-3 rate by origination quarter, flagging cohorts
    // whose deterioration is a robust-z outlier vs other vintages (a classic
    // underwriting-quality-drift signal). NOTE: a full ECL recompute (PD×LGD×EAD
    // vs booked provision) and a 2-period roll-rate transition matrix need
    // provision/PD/LGD/EAD and prior-period stage columns the current feed lacks —
    // see NON_ENGINE_THRESHOLDS 'needs-input'.
    aggregate(rows, t) {
      const out = [];
      const flag = t.sector_npl_flag ?? 2.0;
      const bySector = {};
      for (const r of rows) { const s = str(r.sector); if (!s) continue; const e = num(r.exposure_lkr) ?? 0; (bySector[s] ||= { total: 0, npl: 0 }); bySector[s].total += e; if (num(r.assigned_stage) === 3) bySector[s].npl += e; }
      for (const [sector, agg] of Object.entries(bySector)) {
        if (agg.total <= 0) continue;
        const nplPct = (agg.npl / agg.total) * 100;
        if (nplPct < flag) continue;
        out.push({
          row: { loan_id: `SECTOR:${sector}`, sector },
          rowIndex: -1,
          severity: nplPct >= flag * 2 ? 'critical' : 'high',
          exposure: Math.round(agg.npl),
          finding: `Sector "${sector}": Stage-3 NPL rate ${nplPct.toFixed(1)}% (LKR ${Math.round(agg.npl).toLocaleString()} of ${Math.round(agg.total).toLocaleString()}) exceeds the sector concentration flag.`,
          recommended_action: 'Review sector concentration and provisioning; consider a sector-level management overlay.',
          triggeredBy: [{ field: 'sector_npl_pct', value: Math.round(nplPct * 10) / 10, op: '>=', threshold: flag, rule: 'Sector NPL rate above the concentration flag' }],
        });
      }
      // (b) Vintage cohorts by origination_quarter → Stage-3 rate (by count).
      const byVintage = {};
      for (const r of rows) { const q = str(r.origination_quarter); if (!q) continue; (byVintage[q] ||= { n: 0, s3: 0, exp: 0 }); byVintage[q].n++; if (num(r.assigned_stage) === 3) byVintage[q].s3++; byVintage[q].exp += num(r.exposure_lkr) ?? 0; }
      const cohorts = Object.entries(byVintage).filter(([, a]) => a.n >= 5);
      if (cohorts.length >= 4) {
        const ratesPct = cohorts.map(([, a]) => (a.s3 / a.n) * 100);
        for (const [q, a] of cohorts) {
          const ratePct = (a.s3 / a.n) * 100;
          const ro = robustOutlier(ratePct, ratesPct, { minN: 4, upper: true, field: 'vintage_stage3_rate_pct', label: `Origination cohort ${q} Stage-3 rate is a robust-z outlier vs other vintages (underwriting-quality drift)` });
          if (!ro) continue;
          out.push({
            row: { loan_id: `VINTAGE:${q}`, origination_quarter: q },
            rowIndex: -1,
            severity: Math.abs(ro.z) >= DEFAULT_OUTLIER_Z * 1.7 ? 'critical' : 'high',
            exposure: Math.round(a.exp),
            finding: `Origination vintage ${q}: Stage-3 rate ${ratePct.toFixed(1)}% (${a.s3}/${a.n}) is a robust-z outlier (z=${ro.z.toFixed(1)}) vs other cohorts — underwriting-quality drift in this origination period.`,
            recommended_action: 'Review the underwriting standards and approvals for this origination quarter; assess cohort-level provisioning overlay.',
            triggeredBy: [ro.tb],
            statistic: ro.statistic,
          });
        }
      }
      return out;
    },
  },

  // ── SUSPENSE: phantom-receivable / CBSL aging breach ────────────────────────
  suspense: {
    key: 'account_id', listKey: 'flagged_accounts', summaryKey: 'reconciliation_summary',
    exposureField: 'current_balance_lkr', domains: ['operations'],
    peerStats: ['growth_rate_30d_pct'],
    label: r => `Suspense ${str(r.account_id) || '?'}`,
    detect(r, t, ctx) {
      const aging = num(r.aging_days), growth = num(r.growth_rate_30d_pct), clearing = num(r.clearing_ratio), bal = num(r.current_balance_lkr);
      const agingMax = t.aging_breach_days ?? 90, growthMax = t.growth_pct_30d ?? 50, clearMin = t.clearing_ratio_min ?? 0.30, material = t.size_material_lkr ?? 1e8;
      const tb = []; let sev = 'medium'; let statistic = null;
      if (aging != null && aging >= agingMax) { tb.push({ field: 'aging_days', value: aging, op: '>=', threshold: agingMax, rule: 'CBSL suspense aging limit breached' }); sev = worse(sev, 'high'); }
      if (clearing != null && clearing < clearMin) { tb.push({ field: 'clearing_ratio', value: clearing, op: '<', threshold: clearMin, rule: 'Clearing ratio below floor (phantom-receivable signal)' }); sev = worse(sev, 'high'); }
      // 30-day growth: registry growth_pct_30d is the hard FLOOR; a robust-z
      // outlier vs the population of growth rates adds statistically-anomalous
      // accounts the fixed % would miss (min effect = half the floor).
      const floorGrowth = growth != null && growth >= growthMax;
      if (floorGrowth) { tb.push({ field: 'growth_rate_30d_pct', value: growth, op: '>=', threshold: growthMax, rule: '30-day balance growth above the configured limit' }); sev = worse(sev, 'medium'); }
      const roG = peerOutlier(growth, ctx?.peerStats?.growth_rate_30d_pct, { field: 'growth_rate_30d_pct', label: '30-day balance growth is a robust-z outlier vs the suspense population' });
      if (roG && growth != null && growth >= growthMax * 0.5) { if (!floorGrowth) tb.push(roG.tb); statistic = roG.statistic; sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      // Material + multi-signal → critical (definitive extraction-pool pattern).
      if (bal != null && bal >= material && tb.length >= 2) sev = 'critical';
      return {
        severity: sev,
        finding: `Suspense account ${str(r.account_id)} flagged: ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Require reconciliation within the CBSL window; investigate counterparty and re-aging history.',
        triggeredBy: tb,
        statistic: statistic || undefined,
      };
    },
  },

  // ── KYC: stale CDD / undisclosed BO / PEP without EDD ───────────────────────
  kyc: {
    key: 'customer_id', listKey: 'kyc_gaps', summaryKey: 'compliance_summary',
    domains: ['compliance'],
    label: r => `Customer ${str(r.customer_id) || '?'}`,
    detect(r, t, ctx) {
      const stale = daysSince(r.kyc_last_refresh_date, ctx.asOfMs);
      const eddMax = t.edd_stale_days ?? 365;
      const pep = bool(r.pep_flag), boDisclosed = r.beneficial_owner_disclosed == null ? true : bool(r.beneficial_owner_disclosed);
      const tb = []; let sev = 'medium';
      if (stale != null && stale >= eddMax) { tb.push({ field: 'kyc_last_refresh_date', value: stale, op: '>=', threshold: eddMax, rule: 'KYC/EDD refresh overdue (days since last refresh)' }); sev = worse(sev, pep ? 'high' : 'medium'); }
      if (pep && stale != null && stale >= eddMax) { tb.push({ field: 'pep_flag', value: 1, op: '==', threshold: 1, rule: 'PEP with overdue enhanced due diligence' }); sev = 'high'; }
      if (!boDisclosed) { tb.push({ field: 'beneficial_owner_disclosed', value: 0, op: '==', threshold: 1, rule: 'Beneficial ownership not disclosed (FATF)' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Customer ${str(r.customer_id)}: ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Trigger CDD/EDD remediation; obtain BO disclosure; escalate PEP cases to Compliance.',
        triggeredBy: tb,
      };
    },
    // Population/cross-row pass: introducer-gap concentration, portfolio BO-gap
    // rate, and (cross-feed) sanctions screening from ctx.sanctionsRows.
    aggregate(rows, t, ctx) {
      const out = [];
      const eddMax = t.edd_stale_days ?? 365;
      const hasGap = (r) => { const stale = daysSince(r.kyc_last_refresh_date, ctx.asOfMs); const bo = r.beneficial_owner_disclosed == null ? true : bool(r.beneficial_owner_disclosed); return (stale != null && stale >= eddMax) || !bo; };
      // (a) introducer concentration. Beyond the fixed gap-rate floor, a BINOMIAL
      // test asks "is this introducer's gap count surprisingly high vs the bank-
      // wide base rate?" — principled, p-value-bearing, and FDR-controlled, so an
      // introducer running materially above the portfolio norm is caught even
      // below the fixed %, while the fixed gapPctMin stays a hard floor.
      const gapPctMin = t.introducer_gap_pct ?? 15, minCount = t.introducer_min_count ?? 3;
      const byIntro = {};
      for (const r of rows) { const k = str(r.introducer_code); if (!k) continue; (byIntro[k] ||= { total: 0, gaps: 0 }); byIntro[k].total++; if (hasGap(r)) byIntro[k].gaps++; }
      const portGaps = Object.values(byIntro).reduce((s, a) => s + a.gaps, 0);
      const portTotal = Object.values(byIntro).reduce((s, a) => s + a.total, 0);
      const baseRate = portTotal > 0 ? portGaps / portTotal : 0;
      const alphaK = t.benford_pvalue ?? 0.05; // reuse the agent's significance level
      for (const [code, agg] of Object.entries(byIntro)) {
        if (agg.total === 0) continue;
        const pct = (agg.gaps / agg.total) * 100;
        const floorHit = pct >= gapPctMin && agg.gaps >= minCount;
        // Binomial upper-tail p: probability of ≥ this many gaps at the base rate.
        const binP = (baseRate > 0 && baseRate < 1 && agg.total >= 5) ? binomialSf(agg.gaps, agg.total, baseRate) : null;
        const statHit = binP != null && binP < alphaK && agg.gaps >= minCount && pct > baseRate * 100;
        if (!floorHit && !statHit) continue;
        const tb = [];
        if (floorHit) tb.push({ field: 'introducer_gap_pct', value: Math.round(pct), op: '>=', threshold: gapPctMin, rule: 'Introducer gap rate above the concentration threshold' });
        tb.push({ field: 'introducer_gap_count', value: agg.gaps, op: '>=', threshold: minCount, rule: 'Minimum gap accounts to flag an introducer' });
        if (statHit) tb.push({ field: 'introducer_gap_binomial_p', value: Math.round(binP * 1e6) / 1e6, op: '<', threshold: alphaK, rule: `Gap count is statistically improbable vs the portfolio base rate (${(baseRate * 100).toFixed(1)}%) — binomial p below α` });
        const sev = (floorHit && pct >= gapPctMin * 2) || (statHit && binP < alphaK / 10) ? 'critical' : 'high';
        out.push({ row: { customer_id: `INTRODUCER:${code}` }, rowIndex: -1, severity: sev,
          finding: `Introducer ${code}: ${agg.gaps}/${agg.total} introduced accounts have CDD gaps (${pct.toFixed(0)}%${statHit ? `, p=${binP.toExponential(2)} vs base rate ${(baseRate * 100).toFixed(1)}%` : ''}) — concentration consistent with deliberate problem-account routing.`,
          recommended_action: 'Review the introducer relationship; sample-test introduced accounts; consider suspension.',
          triggeredBy: tb,
          statistic: statHit ? { test: 'binomial-gap-rate', value: agg.gaps, p: binP, peerMedian: Math.round(baseRate * 1000) / 1000 } : undefined });
      }
      // (b) portfolio beneficial-ownership gap rate
      const boTol = t.bo_gap_tolerance ?? 2;
      const boTotal = rows.length, boGaps = rows.filter(r => !(r.beneficial_owner_disclosed == null ? true : bool(r.beneficial_owner_disclosed))).length;
      if (boTotal > 0) { const boPct = (boGaps / boTotal) * 100; if (boPct > boTol) out.push({ row: { customer_id: 'PORTFOLIO:BO' }, rowIndex: -1, severity: boPct > boTol * 2 ? 'critical' : 'high', finding: `Portfolio beneficial-ownership gap rate ${boPct.toFixed(1)}% (${boGaps}/${boTotal}) exceeds the tolerance — FATF BO disclosure shortfall.`, recommended_action: 'Run a BO-disclosure remediation campaign; prioritise high-risk and corporate customers.', triggeredBy: [{ field: 'bo_gap_rate_pct', value: Math.round(boPct * 10) / 10, op: '>', threshold: boTol, rule: 'Portfolio BO-gap rate above tolerance' }] }); }
      // (c) sanctions screening (cross-feed)
      const sancMin = t.sanctions_match_min ?? 0.82;
      for (const s of (ctx.sanctionsRows || [])) {
        const score = num(s.match_score); const cleared = /cleared|false.?positive|closed.?no/i.test(str(s.review_status));
        if (score != null && score >= sancMin && !cleared) {
          out.push({ row: { customer_id: str(s.customer_id) || `SANCTION:${str(s.match_target_name)}` }, rowIndex: -1, severity: 'critical',
            finding: `Sanctions screening: customer ${str(s.customer_id)} matches "${str(s.match_target_name)}" (${str(s.list_source)}) at score ${score} ≥ review floor, status "${str(s.review_status) || 'unreviewed'}".`,
            recommended_action: 'Escalate to Compliance for sanctions adjudication; freeze pending review; file with the FIU if confirmed.',
            triggeredBy: [{ field: 'match_score', value: score, op: '>=', threshold: sancMin, rule: 'Sanctions fuzzy-match score at/above the manual-review floor' }] });
        }
      }
      return out;
    },
  },

  // ── INTERNAL CONTROLS: maker = checker (SoD violation) ──────────────────────
  controls: {
    key: 'transaction_id', listKey: 'sod_violations', summaryKey: 'controls_summary',
    exposureField: 'amount_lkr', domains: ['operations'],
    label: r => `Txn ${str(r.transaction_id) || '?'} @ ${str(r.branch_code)}`,
    detect(r) {
      const init = str(r.initiator_id), appr = str(r.approver_id);
      const tb = [];
      if (init && appr && init === appr) {
        tb.push({ field: 'approver_id', value: appr, op: '==', threshold: init, rule: 'Segregation of duties: initiator equals approver' });
      }
      if (tb.length === 0) return null;
      const amt = num(r.amount_lkr);
      return {
        severity: amt != null && amt >= 1e7 ? 'critical' : 'high',
        finding: `SoD violation at ${str(r.branch_code)}: staff ${init} both initiated and approved transaction ${str(r.transaction_id)}.`,
        recommended_action: 'Independent re-approval; review the branch approval matrix and the approver entitlement.',
        triggeredBy: tb,
      };
    },
    // Per-branch control composite (0–100): SoD violations, override
    // concentration by one approver, and off-hours activity. Flags branches that
    // score below the composite floor.
    aggregate(rows, t) {
      const floor = t.branch_composite_score ?? 65;
      const sodFlag = t.sod_violation_flag ?? 3;
      const ovConc = (t.override_concentration_pct ?? 70) / 100;
      const offMax = (t.off_hours_pct ?? 15) / 100;
      const byBranch = {};
      for (const r of rows) {
        const b = str(r.branch_code); if (!b) continue;
        const g = (byBranch[b] ||= { n: 0, sod: 0, ov: 0, off: 0, byAppr: {} });
        g.n++;
        if (str(r.initiator_id) && str(r.initiator_id) === str(r.approver_id)) g.sod++;
        if (bool(r.override_flag)) { g.ov++; const a = str(r.approver_id); if (a) g.byAppr[a] = (g.byAppr[a] || 0) + 1; }
        const hh = hourOf(r.timestamp); if (hh != null && (hh < 6 || hh >= 21)) g.off++;
      }
      // Peer baseline: off-hours rate across branches (with ≥5 actions) — lets a
      // branch be flagged because its off-hours share is a statistical outlier vs
      // PEER branches, not only against the fixed limit.
      const offRatesPct = Object.values(byBranch).filter(g => g.n >= 5).map(g => (g.off / g.n) * 100);
      const out = [];
      for (const [branch, g] of Object.entries(byBranch)) {
        if (g.n < 5) continue; // too few actions to score a branch
        const offRate = g.off / g.n;
        const topApprOv = Object.values(g.byAppr).sort((a, b) => b - a)[0] || 0;
        const ovConcShare = g.ov > 0 ? topApprOv / g.ov : 0;
        const tb = []; let penalty = 0; let statistic = null;
        if (g.sod >= sodFlag) { penalty += Math.min(30, 10 * (g.sod / sodFlag)); tb.push({ field: 'sod_violations', value: g.sod, op: '>=', threshold: sodFlag, rule: 'SoD violations at the branch ≥ flag' }); }
        if (g.ov >= 3 && ovConcShare >= ovConc) { penalty += 30; tb.push({ field: 'override_concentration_pct', value: Math.round(ovConcShare * 100), op: '>=', threshold: Math.round(ovConc * 100), rule: 'Override concentration by one approver (insider-fraud signal)' }); }
        if (offRate >= offMax) { penalty += Math.min(20, 20 * (offRate / offMax)); tb.push({ field: 'off_hours_pct', value: Math.round(offRate * 100), op: '>=', threshold: Math.round(offMax * 100), rule: 'Off-hours approval share above the branch limit' }); }
        // Peer-relative off-hours outlier (adds a penalty + statistic when a branch
        // is statistically extreme vs peers even below the fixed off_hours_pct).
        const roOff = robustOutlier(offRate * 100, offRatesPct, { minN: 8, field: 'off_hours_pct', upper: true, label: 'Off-hours approval share is a robust-z outlier vs peer branches' });
        if (roOff && offRate >= offMax * 0.5) { penalty += 15; tb.push(roOff.tb); statistic = roOff.statistic; }
        const score = Math.max(0, Math.round(100 - penalty));
        if (score >= floor || tb.length === 0) continue;
        out.push({
          row: { transaction_id: `BRANCH:${branch}`, branch_code: branch, composite_score: score },
          rowIndex: -1,
          severity: score < floor - 15 ? 'critical' : 'high',
          finding: `Branch ${branch}: control composite ${score}/100 below the ${floor} floor — ${tb.map(x => x.rule).join('; ')}.`,
          recommended_action: 'Field audit of the branch control environment; review the approver matrix and override authority.',
          triggeredBy: [...tb, { field: 'branch_composite_score', value: score, op: '<', threshold: floor, rule: 'Branch control composite below floor' }],
          statistic: statistic || undefined,
          extra: { composite_score: score },
        });
      }
      return out;
    },
  },

  // ── MJE: late posting / maker=checker / round-amount / materiality ─────────
  mje: {
    key: 'entry_id', listKey: 'mje_entries', summaryKey: 'mje_summary',
    exposureField: 'amount_lkr', domains: ['finance'],
    label: r => `MJE ${str(r.entry_id) || '?'}`,
    detect(r, t) {
      const amt = num(r.amount_lkr), material = t.manual_material_lkr ?? 1e7, lateHour = t.late_entry_hour ?? 19;
      const maker = str(r.maker_id), appr = str(r.approver_id), automated = bool(r.is_automated);
      let hour = null;
      const m = String(r.entry_time || '').match(/(\d{1,2}):/); if (m) hour = parseInt(m[1], 10);
      const tb = []; let sev = 'medium';
      if (!automated && maker && appr && maker === appr) { tb.push({ field: 'approver_id', value: appr, op: '==', threshold: maker, rule: 'Maker-checker breach: maker equals approver' }); sev = worse(sev, 'high'); }
      if (hour != null && hour >= lateHour) { tb.push({ field: 'entry_time', value: hour, op: '>=', threshold: lateHour, rule: 'After-hours manual posting' }); sev = worse(sev, 'medium'); }
      if (amt != null && amt >= material && !automated) { tb.push({ field: 'amount_lkr', value: amt, op: '>=', threshold: material, rule: 'Manual journal at/above materiality requires maker-checker' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      if (tb.length >= 2 && amt != null && amt >= material) sev = 'critical';
      return {
        severity: sev,
        finding: `Manual journal ${str(r.entry_id)} (${str(r.gl_name)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Obtain independent approval and supporting documentation; confirm GL impact.',
        triggeredBy: tb,
      };
    },
    // (a) Round-number concentration heuristic + (b) Nigrini Benford digit
    // analysis on manual-journal amounts (first-digit always; first-two-digit when
    // ≥300 entries). The digit tests carry exact p-values → calibrated confidence
    // and FDR control.
    aggregate(rows, t) {
      const out = [];
      const pctMax = t.round_amount_pct ?? 15;
      const manual = rows.filter(r => !bool(r.is_automated) && (num(r.amount_lkr) ?? 0) > 0);
      if (manual.length < 20) return out;
      const isRound = (a) => a % 100000 === 0 || a % 1000000 === 0;
      const round = manual.filter(r => isRound(num(r.amount_lkr))).length;
      const pct = (round / manual.length) * 100;
      if (pct >= pctMax) out.push({
        row: { entry_id: 'POPULATION:ROUND' }, rowIndex: -1,
        severity: pct >= pctMax * 2 ? 'critical' : 'high',
        finding: `Round-amount concentration: ${pct.toFixed(0)}% of ${manual.length} manual journals are exact round numbers (${round}) — above the ${pctMax}% anomaly threshold; possible fabricated/plug entries.`,
        recommended_action: 'Sample round-amount entries for supporting documentation; review period-end adjustment patterns.',
        triggeredBy: [{ field: 'round_amount_pct', value: Math.round(pct), op: '>=', threshold: pctMax, rule: 'Round-number concentration above the anomaly threshold' }],
      });
      const amounts = manual.map(r => num(r.amount_lkr));
      const alpha = t.benford_pvalue ?? 0.05;
      for (const digits of [1, 2]) {
        const b = benfordTest(amounts, digits);
        if (b && b.p < alpha) {
          const label = digits === 2 ? 'first-two-digit' : 'first-digit';
          out.push({
            row: { entry_id: `POPULATION:BENFORD${digits === 2 ? '2' : '1'}` }, rowIndex: -1,
            severity: b.p < alpha / 10 ? 'critical' : 'high',
            finding: `Benford ${label} deviation across ${b.n.toLocaleString()} manual-journal amounts (χ²=${b.chi2}, df=${b.df}, p=${b.p.toExponential(2)} < α=${alpha}) — amount distribution inconsistent with naturally-occurring journals; possible fabricated/plug entries.`,
            recommended_action: 'Sample the highest-deviation digit cohorts for supporting documentation; review period-end adjustments and manual postings.',
            triggeredBy: [{ field: `benford_${label}_p`, value: Math.round(b.p * 1e6) / 1e6, op: '<', threshold: alpha, rule: `Benford ${label} χ²=${b.chi2} (df=${b.df}); p-value below the significance level α` }],
            statistic: { test: `benford-${label}`, value: b.chi2, df: b.df, p: b.p },
            extra: { benford_dist: b.dist, benford_digits: digits },
          });
        }
      }
      return out;
    },
  },

  // ── COLLATERAL: LTV breach / stale valuation / double pledge ────────────────
  collateral: {
    key: 'collateral_id', listKey: 'ltv_breaches', summaryKey: 'collateral_summary',
    exposureField: 'exposure_lkr', domains: ['commercial', 'corporate'],
    label: r => `Collateral ${str(r.collateral_id) || '?'}`,
    detect(r, t, ctx) {
      const ltv = num(r.ltv_ratio), pledge = num(r.pledge_count);
      const ltvMax = (t.ltv_breach_pct ?? 85) / 100, staleMax = t.stale_days ?? 365, pledgeMax = t.pledge_max_count ?? 1;
      const staleDays = num(r.days_since_valuation) ?? daysSince(r.valuation_date, ctx.asOfMs);
      const staleFlag = bool(r.stale_flag);
      const tb = []; let sev = 'medium';
      if (ltv != null && ltv >= ltvMax) { tb.push({ field: 'ltv_ratio', value: ltv, op: '>=', threshold: ltvMax, rule: 'LTV at/above breach threshold' }); sev = worse(sev, ltv >= ltvMax + 0.1 ? 'critical' : 'high'); }
      if ((staleDays != null && staleDays >= staleMax) || staleFlag) { tb.push({ field: 'valuation_date', value: staleDays ?? 'flagged', op: '>=', threshold: staleMax, rule: 'Collateral valuation stale' }); sev = worse(sev, 'high'); }
      if (pledge != null && pledge > pledgeMax) { tb.push({ field: 'pledge_count', value: pledge, op: '>', threshold: pledgeMax, rule: 'Collateral pledged more than once (double-pledge)' }); sev = worse(sev, 'critical'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Collateral ${str(r.collateral_id)} (loan ${str(r.loan_id)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Commission revaluation; confirm sole pledge; adjust facility coverage.',
        triggeredBy: tb,
      };
    },
  },

  // ── CONNECTED PARTY: single-obligor / shared-director / disclosure gap ──────
  connectedParty: {
    key: 'customer_id', listKey: 'single_obligor_breaches', summaryKey: 'connected_summary',
    exposureField: 'aggregate_exposure_lkr', domains: ['corporate', 'risk'],
    label: r => `Group ${str(r.group_id) || str(r.customer_id) || '?'}`,
    detect(r, t, ctx) {
      const soPct = num(r.single_obligor_pct), sdCount = num(r.shared_director_count);
      const sdMin = t.shared_director_flag ?? 2;
      // Single-obligor is a CBSL CEILING (large-exposure limit). The Risk
      // Appetite page can set a TIGHTER internal limit below the 25% statutory
      // ceiling; flag at the internal limit (high), CRITICAL at the CBSL ceiling.
      const soFloor = ctx?.appetite?.single_obligor;
      const soCeiling = (soFloor && typeof soFloor.value === 'number') ? soFloor.value : (t.single_obligor_pct ?? 25);
      const soLimit = (soFloor && typeof soFloor.internal_appetite === 'number') ? soFloor.internal_appetite : (t.single_obligor_pct ?? 25);
      const disclosure = str(r.cbsl_disclosure_status).toLowerCase();
      const tb = []; let sev = 'medium';
      if (soPct != null && soPct >= soLimit) { tb.push({ field: 'single_obligor_pct', value: soPct, op: '>=', threshold: soLimit, rule: `Single-obligor exposure ${soPct >= soCeiling ? 'at/above the CBSL large-exposure limit' : 'above internal appetite'}` }); sev = worse(sev, soPct >= soCeiling ? 'critical' : 'high'); }
      if (sdCount != null && sdCount >= sdMin) { tb.push({ field: 'shared_director_count', value: sdCount, op: '>=', threshold: sdMin, rule: 'Shared-director network (connected group)' }); sev = worse(sev, 'high'); }
      if (disclosure && /gap|missing|none|undisclosed|no/.test(disclosure)) { tb.push({ field: 'cbsl_disclosure_status', value: disclosure, op: '==', threshold: 'disclosed', rule: 'Related-party CBSL disclosure gap' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Connected party ${str(r.customer_id)}${r.group_id ? ` (group ${str(r.group_id)})` : ''}: ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Aggregate group exposure; confirm CBSL related-party disclosure; reassess single-obligor limit.',
        triggeredBy: tb,
      };
    },
    // Aggregate connected-GROUP exposure: members' single-obligor %s summed give
    // the group's combined % of the capital base, flagged above the aggregate limit.
    aggregate(rows, t, ctx) {
      // Connected-group aggregate is also a CBSL ceiling; Risk Appetite can set
      // a tighter internal group limit. Flag above the limit (high), CRITICAL
      // above the CBSL ceiling.
      const cgFloor = ctx?.appetite?.connected_group;
      const aggCeiling = (cgFloor && typeof cgFloor.value === 'number') ? cgFloor.value : (t.aggregate_pct ?? 40);
      const aggMax = (cgFloor && typeof cgFloor.internal_appetite === 'number') ? cgFloor.internal_appetite : (t.aggregate_pct ?? 40);
      const byGroup = {};
      for (const r of rows) { const g = str(r.group_id); if (!g) continue; const p = num(r.single_obligor_pct) ?? 0; const e = num(r.aggregate_exposure_lkr) ?? 0; (byGroup[g] ||= { pct: 0, exp: 0, members: 0 }); byGroup[g].pct += p; byGroup[g].exp += e; byGroup[g].members++; }
      const out = [];
      for (const [group, agg] of Object.entries(byGroup)) {
        if (agg.members < 2 || agg.pct < aggMax) continue;
        out.push({ row: { customer_id: `GROUP:${group}`, group_id: group }, rowIndex: -1, severity: agg.pct >= aggCeiling ? 'critical' : 'high',
          exposure: Math.round(agg.exp),
          finding: `Connected group ${group} (${agg.members} members): aggregate exposure ${agg.pct.toFixed(1)}% of capital ${agg.pct >= aggCeiling ? 'exceeds the CBSL connected-group limit' : 'exceeds internal appetite'}.`,
          recommended_action: 'Confirm group structure and CBSL related-party aggregation; reassess against the large-exposure limit.',
          triggeredBy: [{ field: 'aggregate_group_pct', value: Math.round(agg.pct * 10) / 10, op: '>=', threshold: aggMax, rule: 'Aggregate connected-group exposure above the limit' }] });
      }
      return out;
    },
  },

  // ── ALM / IRRBB: repricing gap / EVE / NII sensitivity per bucket ──────────
  alm: {
    key: 'bucket', listKey: 'bucket_gaps', summaryKey: 'alm_summary',
    domains: ['treasury'],
    label: r => `Bucket ${str(r.bucket) || '?'}`,
    detect(r, t) {
      const cumPct = num(r.cumulative_gap_pct), eve = num(r.eve_sensitivity_bps), nii = num(r.nii_impact_pct);
      const cumMax = t.cumulative_gap_pct ?? 20, eveMax = t.eve_sensitivity_bps ?? 15, niiMax = t.nii_sensitivity_pct ?? 10;
      const tb = []; let sev = 'medium';
      if (cumPct != null && Math.abs(cumPct) >= cumMax) { tb.push({ field: 'cumulative_gap_pct', value: cumPct, op: '>=', threshold: cumMax, rule: 'Cumulative repricing gap limit breached' }); sev = worse(sev, 'high'); }
      if (eve != null && Math.abs(eve) >= eveMax) { tb.push({ field: 'eve_sensitivity_bps', value: eve, op: '>=', threshold: eveMax, rule: 'EVE sensitivity beyond appetite' }); sev = worse(sev, 'high'); }
      if (nii != null && Math.abs(nii) >= niiMax) { tb.push({ field: 'nii_impact_pct', value: nii, op: '>=', threshold: niiMax, rule: 'NII sensitivity beyond appetite' }); sev = worse(sev, 'medium'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `ALM bucket ${str(r.bucket)}: ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Review hedging and repricing profile for this bucket; report to ALCO.',
        triggeredBy: tb,
      };
    },
  },

  // ── THIRD PARTY: concentration / stale assessment / exit readiness ──────────
  thirdParty: {
    key: 'vendor_id', listKey: 'concentration_flags', summaryKey: 'vendor_summary',
    exposureField: 'annual_spend_lkr', domains: ['operations', 'technology'],
    peerStats: ['concentration_pct'],
    label: r => `Vendor ${str(r.vendor_id) || '?'}`,
    detect(r, t, ctx) {
      const conc = num(r.concentration_pct), spend = num(r.annual_spend_lkr);
      const concMax = t.concentration_pct ?? 60, staleMax = t.assessment_stale ?? 365, exitMax = t.critical_exit_days ?? 180;
      const staleDays = daysSince(r.last_assessment_date, ctx.asOfMs);
      const toEnd = daysUntil(r.contract_end_date, ctx.asOfMs);
      const critical = /critical|high/i.test(str(r.criticality));
      const tb = []; let sev = 'medium'; let statistic = null;
      // Concentration: registry concentration_pct is the hard FLOOR; a robust-z
      // outlier vs the vendor population adds vendors that are statistically
      // over-concentrated relative to peers even below the fixed %.
      const floorConc = conc != null && conc >= concMax;
      if (floorConc) { tb.push({ field: 'concentration_pct', value: conc, op: '>=', threshold: concMax, rule: 'Vendor concentration in category above the configured limit' }); sev = worse(sev, 'high'); }
      const roC = peerOutlier(conc, ctx?.peerStats?.concentration_pct, { field: 'concentration_pct', label: 'Vendor concentration is a robust-z outlier vs the vendor population' });
      if (roC && conc != null && conc >= concMax * 0.5) { if (!floorConc) tb.push(roC.tb); statistic = roC.statistic; sev = worse(sev, 'high'); }
      if (staleDays != null && staleDays >= staleMax) { tb.push({ field: 'last_assessment_date', value: staleDays, op: '>=', threshold: staleMax, rule: 'Vendor risk assessment overdue' }); sev = worse(sev, 'medium'); }
      if (critical && toEnd != null && toEnd <= exitMax) { tb.push({ field: 'contract_end_date', value: toEnd, op: '<=', threshold: exitMax, rule: 'Critical vendor contract ending without exit readiness' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Vendor ${str(r.vendor_id)} (${str(r.category)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Refresh vendor risk assessment; confirm exit/continuity plan; review concentration.',
        triggeredBy: tb,
        statistic: statistic || undefined,
      };
    },
  },

  // ── ACCESS RIGHTS: dormant-privileged / overdue review / toxic combo / SoD ──
  accessRights: {
    key: 'user_id', listKey: 'dormant_privileged', summaryKey: 'access_summary',
    domains: ['technology', 'operations'],
    label: r => `User ${str(r.user_id) || '?'}`,
    detect(r, t) {
      const login = num(r.last_login_days), review = num(r.last_review_days);
      const dormantMax = t.dormant_days ?? 90, reviewMax = t.priv_review_days ?? 90, toxicMax = t.toxic_combo_max ?? 0;
      const privileged = /admin|privileg|super|root/i.test(str(r.privilege_level) + ' ' + str(r.role));
      const toxic = str(r.toxic_combination_code);
      const sodConflict = bool(r.sod_conflict_flag);
      const tb = []; let sev = 'medium';
      if (toxic && toxicMax === 0) { tb.push({ field: 'toxic_combination_code', value: toxic, op: '!=', threshold: 'none', rule: 'Toxic entitlement combination present' }); sev = worse(sev, 'critical'); }
      if (privileged && login != null && login >= dormantMax) { tb.push({ field: 'last_login_days', value: login, op: '>=', threshold: dormantMax, rule: 'Dormant privileged account' }); sev = worse(sev, login >= dormantMax * 2 ? 'critical' : 'high'); }
      if (review != null && review >= reviewMax) { tb.push({ field: 'last_review_days', value: review, op: '>=', threshold: reviewMax, rule: 'Privileged-access review overdue' }); sev = worse(sev, review >= reviewMax * 3 ? 'critical' : 'high'); }
      if (sodConflict) { tb.push({ field: 'sod_conflict_flag', value: 1, op: '==', threshold: 1, rule: 'Entitlement SoD conflict' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Access ${str(r.user_id)} (${str(r.role)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Revoke/recertify entitlements; disable dormant access; resolve toxic combinations.',
        triggeredBy: tb,
      };
    },
  },

  // ── CONDUCT: recurrence / open-case ageing / whistleblower ──────────────────
  conduct: {
    key: 'case_id', listKey: 'recurring_subjects', summaryKey: 'conduct_summary',
    domains: ['people', 'risk'],
    label: r => `Conduct ${str(r.case_id) || '?'}`,
    detect(r, t) {
      const rec = num(r.recurrence_count), open = num(r.days_open);
      const recMax = t.recurrence_flag ?? 2, dayMax = t.resolution_days ?? 60;
      const wb = bool(r.whistleblower_flag);
      const openStatus = !/closed|resolved/i.test(str(r.resolution_status));
      const tb = []; let sev = 'medium';
      if (rec != null && rec >= recMax) { tb.push({ field: 'recurrence_count', value: rec, op: '>=', threshold: recMax, rule: 'Recurring conduct subject' }); sev = worse(sev, rec >= recMax + 1 ? 'critical' : 'high'); }
      if (openStatus && open != null && open >= dayMax) { tb.push({ field: 'days_open', value: open, op: '>=', threshold: dayMax, rule: 'Conduct case open beyond resolution SLA' }); sev = worse(sev, open >= dayMax * 2 ? 'critical' : 'high'); }
      if (wb) { tb.push({ field: 'whistleblower_flag', value: 1, op: '==', threshold: 1, rule: 'Whistleblower-linked case' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Conduct case ${str(r.case_id)} (${str(r.subject_role)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Escalate per the conduct/grievance policy; track to resolution.',
        triggeredBy: tb,
      };
    },
    // Whistleblower clustering: ≥3 whistleblower cases opened within the window —
    // a spike that may indicate a systemic issue or coordinated reporting.
    aggregate(rows, t) {
      const winDays = t.whistleblower_window ?? 30;
      const wb = rows.filter(r => bool(r.whistleblower_flag)).map(r => Date.parse(str(r.opened_date))).filter(Number.isFinite).sort((a, b) => a - b);
      if (wb.length < 3) return [];
      let burst = 0;
      for (let s = 0; s < wb.length; s++) { let e = s; while (e < wb.length && (wb[e] - wb[s]) <= winDays * 86400000) e++; burst = Math.max(burst, e - s); }
      if (burst < 3) return [];
      return [{ row: { case_id: 'CLUSTER:WB' }, rowIndex: -1, severity: burst >= 5 ? 'critical' : 'high',
        finding: `Whistleblower cluster: ${burst} whistleblower cases opened within ${winDays} days — possible systemic issue or coordinated reporting.`,
        recommended_action: 'Investigate the common root cause; review the implicated unit; protect reporters per policy.',
        triggeredBy: [{ field: 'whistleblower_cases_in_window', value: burst, op: '>=', threshold: 3, rule: `Whistleblower cases clustered within the ${winDays}-day window` }] }];
    },
  },

  // ── WEALTH: suitability gap (product risk > customer profile) ───────────────
  wealth: {
    key: 'customer_id', listKey: 'suitability_flags', summaryKey: 'portfolio_summary',
    exposureField: 'holding_lkr', domains: ['consumer'],
    label: r => `Wealth ${str(r.customer_id) || '?'}`,
    detect(r, t) {
      const profile = num(r.risk_profile), prodRating = num(r.product_risk_rating);
      const gapMax = t.risk_profile_gap ?? 1;
      const churnMax = t.churn_velocity ?? 4, switches = num(r.switches_90d);
      const tb = []; let sev = 'medium';
      if (profile != null && prodRating != null && (prodRating - profile) >= gapMax) {
        const gap = prodRating - profile;
        tb.push({ field: 'product_risk_rating', value: prodRating, op: '>=', threshold: profile + gapMax, rule: 'Product risk exceeds customer profile beyond tolerance' });
        sev = worse(sev, gap >= gapMax + 1 ? 'critical' : 'high');
      }
      if (switches != null && switches >= churnMax) { tb.push({ field: 'switches_90d', value: switches, op: '>=', threshold: churnMax, rule: 'Product-switching velocity (churning) above threshold' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Customer ${str(r.customer_id)} (RM ${str(r.rm_code)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Review suitability with the RM; remediate mis-sold holdings (CBSL Direction 1/2021); check for churning.',
        triggeredBy: tb,
      };
    },
    // Single-product concentration per customer (share of holdings in one product).
    // The registry concentration_pct is the hard FLOOR; a robust-z outlier vs the
    // peer customers' concentration distribution adds the statistically over-
    // concentrated even below the fixed limit (min effect = half the floor).
    aggregate(rows, t) {
      const concMax = (t.concentration_pct ?? 40) / 100;
      const byCust = {};
      for (const r of rows) { const c = str(r.customer_id); if (!c) continue; const h = num(r.holding_lkr) ?? 0; (byCust[c] ||= { total: 0, byProd: {} }); byCust[c].total += h; const p = str(r.product_id); if (p) byCust[c].byProd[p] = (byCust[c].byProd[p] || 0) + h; }
      const eligible = {};
      for (const [cust, agg] of Object.entries(byCust)) {
        if (agg.total <= 0 || Object.keys(agg.byProd).length < 2) continue;
        const top = Object.values(agg.byProd).sort((a, b) => b - a)[0] || 0;
        eligible[cust] = { sharePct: (top / agg.total) * 100, top };
      }
      const sharePcts = Object.values(eligible).map(x => x.sharePct);
      const out = [];
      for (const [cust, { sharePct, top }] of Object.entries(eligible)) {
        const floorHit = sharePct >= concMax * 100;
        const ro = robustOutlier(sharePct, sharePcts, { upper: true, minN: 30, field: 'single_product_concentration_pct', label: 'Single-product concentration is a robust-z outlier vs peer customers' });
        const statHit = !!ro && sharePct >= concMax * 100 * 0.5;
        if (!floorHit && !statHit) continue;
        const tb = [];
        if (floorHit) tb.push({ field: 'single_product_concentration_pct', value: Math.round(sharePct), op: '>=', threshold: Math.round(concMax * 100), rule: 'Single-product concentration above limit' });
        if (statHit) tb.push(ro.tb);
        const sev = floorHit ? (sharePct >= (concMax + 0.2) * 100 ? 'critical' : 'high') : (Math.abs(ro.z) >= DEFAULT_OUTLIER_Z * 1.7 ? 'critical' : 'high');
        out.push({ row: { customer_id: cust }, rowIndex: -1, severity: sev,
          exposure: Math.round(top),
          finding: `Customer ${cust}: ${Math.round(sharePct)}% of wealth holdings concentrated in a single product${statHit ? ` (robust-z ${ro.z.toFixed(1)} vs peers)` : ''} — single-product concentration risk.`,
          recommended_action: 'Review portfolio diversification and suitability with the RM.',
          triggeredBy: tb,
          statistic: statHit ? ro.statistic : undefined });
      }
      return out;
    },
  },

  // ── CREDIT FRAUD: origination integrity composite (transparent weighting) ───
  creditFraud: {
    key: 'loan_id', listKey: 'flagged_facilities', summaryKey: 'origination_summary',
    exposureField: 'facility_lkr', domains: ['audit', 'compliance'],
    label: r => `Facility ${str(r.loan_id) || '?'}`,
    detect(r, t) {
      const facility = num(r.facility_lkr) ?? 0;
      const fpd = bool(r.first_payment_missed), dpdFirst = num(r.days_past_due_first);
      const fpdWin = t.first_payment_default_d ?? 90;
      const siphon = num(r.outflow_to_undisclosed_lkr_72h), siphonPctMin = (t.siphon_outflow_pct ?? 85) / 100;
      const ageMo = num(r.borrower_business_age_months), bo = str(r.borrower_bo_disclosure).toLowerCase();
      const addr = bool(r.address_sharing_flag);
      const peerMed = num(r.sector_peer_median_lkr), peerStd = num(r.sector_peer_std_lkr), sigMax = t.amount_vs_cohort_sigma ?? 3.0;
      const shellMin = t.shell_borrower_score ?? 0.75, critCut = t.composite_critical ?? 0.80;
      const tb = []; let composite = 0;
      if (fpd && dpdFirst != null && dpdFirst >= fpdWin) { tb.push({ field: 'days_past_due_first', value: dpdFirst, op: '>=', threshold: fpdWin, rule: 'First-payment default' }); composite += 0.35; }
      if (siphon != null && facility > 0 && (siphon / facility) >= siphonPctMin) { tb.push({ field: 'outflow_to_undisclosed_lkr_72h', value: Math.round((siphon / facility) * 100), op: '>=', threshold: Math.round(siphonPctMin * 100), rule: 'Post-disbursement siphoning to undisclosed parties (% of facility)' }); composite += 0.35; }
      // Shell-borrower SCORE: BO non-disclosure + young business + address sharing.
      const shellScore = (/no|none|missing|undisclosed/.test(bo) ? 0.45 : 0) + (ageMo != null && ageMo <= 6 ? 0.3 : 0) + (addr ? 0.25 : 0);
      if (shellScore >= shellMin) { tb.push({ field: 'shell_borrower_score', value: Math.round(shellScore * 100) / 100, op: '>=', threshold: shellMin, rule: 'Shell-borrower composite (BO non-disclosure, young entity, address sharing)' }); composite += 0.3; }
      else if (addr) { tb.push({ field: 'address_sharing_flag', value: 1, op: '==', threshold: 1, rule: 'Address shared across borrowers/guarantors' }); composite += 0.1; }
      if (peerMed != null && peerStd && facility > 0) { const sigma = (facility - peerMed) / peerStd; if (sigma >= sigMax) { tb.push({ field: 'facility_lkr', value: Math.round(sigma * 10) / 10, op: '>=', threshold: sigMax, rule: 'Facility size beyond sector-peer cohort (σ)' }); composite += 0.2; } }
      if (tb.length === 0) return null;
      composite = Math.min(1, composite);
      const sev = composite >= critCut ? 'critical' : composite >= critCut - 0.2 ? 'high' : 'medium';
      return {
        severity: sev,
        finding: `Origination ${str(r.loan_id)} (borrower ${str(r.borrower_id)}): composite ${composite.toFixed(2)} from ${tb.length} indicator(s) — ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Refer to fraud investigation; freeze facility; file STR if siphoning confirmed (FTRA §7).',
        triggeredBy: [...tb, { field: 'composite_score', value: Math.round(composite * 100) / 100, op: '>=', threshold: critCut, rule: 'Origination-fraud composite vs critical cutoff' }],
        extra: { composite_score: composite },
      };
    },
    // Guarantor concentration: one guarantor on ≥N distinct facilities (cross-row).
    aggregate(rows, t) {
      const gMax = t.guarantor_concentration ?? 6;
      const byG = {};
      for (const r of rows) { const g = str(r.guarantor_id); if (!g) continue; (byG[g] ||= []).push(str(r.loan_id)); }
      const out = [];
      for (const [g, loans] of Object.entries(byG)) {
        if (loans.length < gMax) continue;
        out.push({ row: { loan_id: `GUARANTOR:${g}` }, rowIndex: -1, severity: loans.length >= gMax * 2 ? 'critical' : 'high',
          finding: `Guarantor ${g} appears on ${loans.length} distinct facilities — guarantor-chain concentration (collusion / shell-guarantor signal).`,
          recommended_action: 'Verify guarantor independence and capacity; review the guarantor-chain for connected-party / fronting risk.',
          triggeredBy: [{ field: 'guarantor_facility_count', value: loans.length, op: '>=', threshold: gMax, rule: 'Single guarantor on ≥ the concentration threshold of facilities' }] });
      }
      return out;
    },
  },

  // ── DIGITAL FRAUD: behavioural anomaly / failed-MFA / unregistered device ───
  digital: {
    key: 'session_id', listKey: 'anomalous_sessions', summaryKey: 'digital_summary',
    exposureField: 'max_transaction_lkr', domains: ['technology', 'consumer'],
    label: r => `Session ${str(r.session_id) || '?'}`,
    detect(r, t) {
      // behavioral_score arrives on a 0–100 scale in the feed; the registry
      // thresholds are 0–1 probabilities — normalise before comparing.
      const raw = num(r.behavioral_score);
      const behav = raw == null ? null : (raw > 1 ? raw / 100 : raw);
      const cutoff = t.session_anomaly_score ?? 0.70;
      const critCut = t.biometric_deviation ?? 0.90; // extreme-deviation → critical
      const mfaTrig = bool(r.mfa_triggered), mfaPass = bool(r.mfa_passed), reg = r.is_registered_device == null ? true : bool(r.is_registered_device);
      const diffCity = str(r.previous_session_city) && str(r.login_city) && str(r.previous_session_city) !== str(r.login_city);
      const mins = num(r.minutes_since_last_session);
      const tb = []; let sev = 'medium';
      // PRIMARY anomaly signals — each is, on its own, a flaggable session. High
      // at the flag cutoff; CRITICAL at the (configurable) extreme-deviation cutoff
      // or improbable travel, so "critical" stays meaningful.
      if (behav != null && behav >= cutoff) { tb.push({ field: 'behavioral_score', value: raw, op: '>=', threshold: Math.round(cutoff * 100), rule: 'Behavioural-biometric deviation (0–100)' }); sev = worse(sev, behav >= critCut ? 'critical' : 'high'); }
      if (mfaTrig && !mfaPass) { tb.push({ field: 'mfa_passed', value: 0, op: '==', threshold: 1, rule: 'MFA challenged and failed' }); sev = worse(sev, 'high'); }
      // Impossible travel via GEO-VELOCITY: great-circle distance between the two
      // cities ÷ elapsed time. Flag when the implied speed exceeds a feasible
      // commercial-travel ceiling (~900 km/h + buffer). When either city is not in
      // the geo table, fall back to the prior fixed-window heuristic (no wrong
      // distance is invented). The configured travel window is the fallback bound.
      const travelWin = 120; // fallback time-window (min) when city geo is unavailable
      if (diffCity && mins != null && mins > 0) {
        const c1 = cityCoords(r.previous_session_city), c2 = cityCoords(r.login_city);
        const km = (c1 && c2) ? haversineKm(c1.lat, c1.lon, c2.lat, c2.lon) : null;
        if (km != null) {
          const kmh = km / (mins / 60);
          if (kmh > 1000) { tb.push({ field: 'travel_speed_kmh', value: Math.round(kmh), op: '>', threshold: 1000, rule: `Impossible travel: ${str(r.previous_session_city)}→${str(r.login_city)} (${Math.round(km)} km in ${mins} min ⇒ ${Math.round(kmh)} km/h, beyond feasible air travel)` }); sev = worse(sev, 'critical'); }
        } else if (mins < travelWin) {
          tb.push({ field: 'minutes_since_last_session', value: mins, op: '<', threshold: travelWin, rule: `Improbable travel: ${str(r.previous_session_city)}→${str(r.login_city)} in ${mins}m (city geo unavailable — time-window fallback)` }); sev = worse(sev, 'high');
        }
      }
      // A new/unregistered device is NOT, by itself, an anomaly (people get new
      // phones). It is only CORROBORATING evidence on an already-flagged session
      // — never a standalone finding, and it does not by itself escalate to
      // critical. (Prevents flooding the queue with every new-device login.)
      if (tb.length === 0) return null;
      if (!reg && (num(r.max_transaction_lkr) ?? 0) > 0) { tb.push({ field: 'is_registered_device', value: 0, op: '==', threshold: 1, rule: 'Corroborating: unregistered device transacting' }); sev = worse(sev, 'high'); }
      return {
        severity: sev,
        finding: `Session ${str(r.session_id)} (account ${str(r.account_id)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Step-up authentication; review account for takeover; contact customer.',
        triggeredBy: tb,
      };
    },
    // Repeated MFA failures on one account within the configured window —
    // brute-force / account-takeover attempt (cross-row).
    aggregate(rows, t) {
      const winMin = t.mfa_fail_window ?? 30;
      const byAcct = {};
      for (const r of rows) { if (!(bool(r.mfa_triggered) && !bool(r.mfa_passed))) continue; const a = str(r.account_id); if (!a) continue; const ts = Date.parse(str(r.timestamp)); (byAcct[a] ||= []).push({ ts: Number.isFinite(ts) ? ts : null, r }); }
      const out = [];
      for (const [acct, fails] of Object.entries(byAcct)) {
        if (fails.length < 3) continue;
        const ts = fails.map(f => f.ts).filter(Number.isFinite).sort((a, b) => a - b);
        // ≥3 failures inside the window (sliding)
        let burst = 0;
        for (let s = 0; s < ts.length; s++) { let e = s; while (e < ts.length && (ts[e] - ts[s]) <= winMin * 60000) e++; burst = Math.max(burst, e - s); }
        if (burst < 3) continue;
        out.push({
          row: { session_id: `ACCOUNT:${acct}`, account_id: acct },
          rowIndex: -1,
          severity: burst >= 5 ? 'critical' : 'high',
          finding: `Account ${acct}: ${burst} MFA failures within ${winMin} min — repeated-failure / account-takeover attempt.`,
          recommended_action: 'Lock the account; force credential reset; contact the customer through a verified channel.',
          triggeredBy: [{ field: 'mfa_failures_in_window', value: burst, op: '>=', threshold: 3, rule: `MFA failures clustered within the ${winMin}-minute window` }],
        });
      }
      return out;
    },
  },

  // ── TRADE / TREASURY: FX position-limit breach (deterministic from columns) ─
  trade: {
    key: 'document_id', listKey: 'treasury_breaches', summaryKey: 'trade_summary',
    domains: ['commercial', 'corporate', 'treasury'],
    label: r => `Doc ${str(r.document_id) || str(r.position_id) || '?'}`,
    detect(r, t) {
      const pos = num(r.position_amount), limit = num(r.approved_limit), fxMax = (t.fx_limit_breach_pct ?? 95) / 100;
      const tb = []; let sev = 'medium';
      if (pos != null && limit && (pos / limit) >= fxMax) { const util = Math.round((pos / limit) * 100); tb.push({ field: 'position_amount', value: util, op: '>=', threshold: Math.round(fxMax * 100), rule: 'FX position utilisation at/above limit (% of approved)' }); sev = worse(sev, pos > limit ? 'critical' : 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Treasury position ${str(r.position_id) || str(r.document_id)} (${str(r.currency_pair)}): ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Reduce position to within limit; review trader limit and dealing authority.',
        triggeredBy: tb,
      };
    },
    // TBML signals: invoice unit-price deviation from the POPULATION median for
    // the same HS code (no external benchmark needed), and duplicate LCs on
    // overlapping shipment periods (cross-row).
    aggregate(rows, t) {
      const out = [];
      const devMax = (t.invoice_deviation_pct ?? 25) / 100;
      const overlapDays = t.duplicate_lc_overlap ?? 7;
      // (a) price deviation vs same-HS-code cohort. Robust modified-z (median+MAD)
      // catches prices that are statistically extreme FOR THEIR cohort — adaptive,
      // not a blanket 25%. The registry invoice_deviation_pct is kept as a hard
      // FLOOR (always flags) and as the minimum effect size for the statistical
      // path (so a tiny deviation in an ultra-tight cohort isn't flagged on z alone).
      const minEffect = devMax * 0.5;
      const byHs = {};
      for (const r of rows) { const hs = str(r.hs_code), p = num(r.declared_unit_price); if (hs && p != null && p > 0) (byHs[hs] ||= []).push({ r, p }); }
      for (const [hs, items] of Object.entries(byHs)) {
        if (items.length < 4) continue; // need a cohort to define a median
        const prices = items.map(x => x.p);
        const sorted = prices.slice().sort((a, b) => a - b);
        const med = sorted[Math.floor(sorted.length / 2)];
        if (!med) continue;
        for (const { r, p } of items) {
          const dev = Math.abs(p - med) / med;
          const floorHit = dev >= devMax;
          const ro = robustOutlier(p, prices, { minN: 8, field: 'declared_unit_price', twoSided: true, label: `Declared unit price is a robust-z outlier within the HS-code cohort (z vs peers; deviates ${Math.round(dev * 100)}% from the cohort median)` });
          const statHit = !!ro && dev >= minEffect;
          if (!floorHit && !statHit) continue;
          const tb = [];
          if (floorHit) tb.push({ field: 'declared_unit_price', value: Math.round(dev * 100), op: '>=', threshold: Math.round(devMax * 100), rule: 'Unit-price deviation from same-HS-code cohort median ≥ tolerance' });
          if (statHit) tb.push(ro.tb);
          const sev = floorHit ? (dev >= devMax * 2 ? 'critical' : 'high') : (Math.abs(ro.z) >= DEFAULT_OUTLIER_Z * 1.7 ? 'critical' : 'high');
          out.push({
            row: { document_id: str(r.document_id), ...r }, rowIndex: -1,
            severity: sev,
            finding: `Invoice ${str(r.document_id)} (HS ${hs}): declared unit price deviates ${Math.round(dev * 100)}% from the cohort median${statHit ? ` (robust-z ${ro.z.toFixed(1)} vs peers)` : ''} — over/under-invoicing (TBML) signal.`,
            recommended_action: 'Verify invoice against customs/COMTRADE benchmarks; review for trade-based money laundering.',
            triggeredBy: tb,
            statistic: statHit ? ro.statistic : undefined,
          });
        }
      }
      // (b) duplicate LCs on overlapping shipment periods (per customer)
      const lcs = rows.filter(r => str(r.lc_reference) && str(r.shipment_period_start));
      for (let i = 0; i < lcs.length; i++) for (let j = i + 1; j < lcs.length; j++) {
        const a = lcs[i], b = lcs[j];
        if (str(a.customer_id) !== str(b.customer_id)) continue;
        const aS = Date.parse(str(a.shipment_period_start)), aE = Date.parse(str(a.shipment_period_end) || str(a.shipment_period_start));
        const bS = Date.parse(str(b.shipment_period_start)), bE = Date.parse(str(b.shipment_period_end) || str(b.shipment_period_start));
        if (![aS, aE, bS, bE].every(Number.isFinite)) continue;
        const overlap = Math.min(aE, bE) - Math.max(aS, bS);
        if (overlap >= -overlapDays * 86400000) { // overlapping (or within tolerance)
          out.push({
            row: { document_id: `${str(a.lc_reference)}~${str(b.lc_reference)}`, customer_id: str(a.customer_id) }, rowIndex: -1,
            severity: 'high',
            finding: `Duplicate LC risk: ${str(a.lc_reference)} and ${str(b.lc_reference)} for ${str(a.customer_id)} have overlapping shipment periods — possible double-financing.`,
            recommended_action: 'Confirm distinct underlying shipments; reconcile LC documents to bills of lading.',
            triggeredBy: [{ field: 'shipment_period_overlap', value: Math.round(overlap / 86400000), op: '<=', threshold: overlapDays, rule: 'Shipment-period overlap within the duplicate-LC window' }],
          });
        }
      }
      return out;
    },
  },

  // ── CAPITAL & LIQUIDITY: Basel III ratios computed from the quarterly inputs ─
  capital: {
    key: 'quarter', listKey: 'key_findings', summaryKey: 'capital_position',
    domains: ['finance', 'risk'],
    label: r => `Quarter ${str(r.quarter) || '?'}`,
    detect(r, t, ctx) {
      const tier1 = num(r.tier1_capital_lkr_bn), tier2 = num(r.tier2_capital_lkr_bn);
      const rwa = (num(r.rwa_credit_lkr_bn) ?? 0) + (num(r.rwa_market_lkr_bn) ?? 0) + (num(r.rwa_operational_lkr_bn) ?? 0);
      const hqla = (num(r.hqla_level1_lkr_bn) ?? 0) + 0.85 * (num(r.hqla_level2a_lkr_bn) ?? 0) + 0.5 * (num(r.hqla_level2b_lkr_bn) ?? 0);
      const nco = num(r.net_cash_outflow_30d_lkr_bn), asf = num(r.available_stable_funding_lkr_bn), rsf = num(r.required_stable_funding_lkr_bn);
      if (!rwa) return null;
      const tier1Ratio = tier1 != null ? (tier1 / rwa) * 100 : null;
      const car = (tier1 != null && tier2 != null) ? ((tier1 + tier2) / rwa) * 100 : null;
      const lcr = nco ? (hqla / nco) * 100 : null;
      const nsfr = rsf ? (asf / rsf) * 100 : null;
      // Risk Appetite drives the flag threshold: prefer the resolved internal
      // appetite (ctx.appetite, from the Risk Appetite page) over the registry
      // min; CRITICAL is reserved for breaching the CBSL regulatory FLOOR.
      const ap = ctx?.appetite || {};
      const appMin = (k, fb) => { const f = ap[k]; return f && typeof f.internal_appetite === 'number' ? f.internal_appetite : fb; };
      const floorOf = (k, fb) => { const f = ap[k]; return f && typeof f.value === 'number' ? f.value : fb; };
      const t1Min = appMin('tier1_car', t.tier1_min ?? 10), carMin = appMin('total_car', t.car_min ?? 14), lcrMin = appMin('lcr', t.lcr_min ?? 100), nsfrMin = appMin('nsfr', t.nsfr_min ?? 100);
      const tb = []; let sev = 'medium';
      const chk = (val, min, floor, field, label) => {
        if (val == null) return;
        if (val < min) { tb.push({ field, value: Math.round(val * 100) / 100, op: '<', threshold: min, rule: `${label} below ${val < floor ? 'the CBSL regulatory floor' : 'internal appetite'}` }); sev = worse(sev, val < floor ? 'critical' : 'high'); }
      };
      chk(tier1Ratio, t1Min, floorOf('tier1_car', t1Min - 2), 'tier1_ratio_pct', 'Tier 1 ratio');
      chk(car, carMin, floorOf('total_car', carMin - 2), 'car_pct', 'Total CAR');
      chk(lcr, lcrMin, floorOf('lcr', lcrMin - 10), 'lcr_pct', 'LCR');
      chk(nsfr, nsfrMin, floorOf('nsfr', nsfrMin - 10), 'nsfr_pct', 'NSFR');
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Quarter ${str(r.quarter)}: ${tb.map(x => `${x.rule} (${x.value} vs ${x.threshold})`).join('; ')}.`,
        recommended_action: 'ALCO remediation; assess capital plan / liquidity buffer; ICAAP disclosure if projected breach.',
        triggeredBy: tb,
        extra: { tier1_pct: tier1Ratio, car_pct: car, lcr_pct: lcr, nsfr_pct: nsfr },
      };
    },
  },

  // ── BALANCE-SHEET DRIVERS: depositor concentration / HQLA quality ───────────
  balance: {
    key: 'quarter', listKey: 'key_findings', summaryKey: 'structural_summary',
    domains: ['finance', 'treasury'],
    label: r => `Quarter ${str(r.quarter) || '?'}`,
    detect(r, t) {
      const conc = num(r.top10_depositor_share_pct), hqla1 = num(r.hqla_level1_share_pct);
      const concMax = t.depositor_concentration_pct ?? 35, hqlaMin = t.hqla_quality_min ?? 60;
      const tb = []; let sev = 'medium';
      if (conc != null && conc >= concMax) { tb.push({ field: 'top10_depositor_share_pct', value: conc, op: '>=', threshold: concMax, rule: 'Top-10 depositor concentration above appetite' }); sev = worse(sev, conc >= concMax + 15 ? 'critical' : 'high'); }
      if (hqla1 != null && hqla1 < hqlaMin) { tb.push({ field: 'hqla_level1_share_pct', value: hqla1, op: '<', threshold: hqlaMin, rule: 'Level-1 HQLA share below quality floor' }); sev = worse(sev, 'high'); }
      if (tb.length === 0) return null;
      return {
        severity: sev,
        finding: `Quarter ${str(r.quarter)}: ${tb.map(x => x.rule).join('; ')}.`,
        recommended_action: 'Diversify funding base; improve HQLA composition; report to ALCO.',
        triggeredBy: tb,
      };
    },
  },

  // ── TRANSACTION SURVEILLANCE: structuring clusters (cross-row aggregation) ──
  // Groups by account; finds ≥N sub-threshold transactions that AGGREGATE above
  // the STR threshold inside the structuring time window — the classic
  // smurfing/structuring pattern. The cluster's transaction_ids + amounts are
  // the evidence; reproducible (sorted, windowed) per the configured thresholds.
  transaction: {
    key: 'account_id', listKey: 'structuring_clusters', summaryKey: 'surveillance_summary',
    domains: ['compliance'],
    detectAll(rows, t) {
      const strThr = t.str_threshold_lkr ?? 5000000;
      const minCount = t.cluster_min_count ?? 3;
      const windowMin = t.cluster_window_min ?? 1440;
      const byAcct = {};
      rows.forEach((r, i) => { const a = str(r.account_id); if (a) (byAcct[a] ||= []).push({ r, i }); });
      const out = [];
      for (const [acct, items] of Object.entries(byAcct)) {
        const sub = items
          .map(x => ({ i: x.i, r: x.r, amt: num(x.r.amount_lkr), ts: Date.parse(str(x.r.timestamp)) }))
          .filter(x => x.amt != null && x.amt > 0 && x.amt < strThr && Number.isFinite(x.ts))
          .sort((a, b) => a.ts - b.ts);
        if (sub.length < minCount) continue;
        // Sliding window: widest qualifying window (≥minCount txns summing ≥STR within windowMin).
        let best = null;
        for (let s = 0; s < sub.length; s++) {
          let sum = 0, cnt = 0, e = s;
          while (e < sub.length && (sub[e].ts - sub[s].ts) <= windowMin * 60000) { sum += sub[e].amt; cnt++; e++; }
          if (cnt >= minCount && sum >= strThr && (!best || sum > best.sum)) best = { s, e, cnt, sum };
        }
        if (!best) continue;
        const cluster = sub.slice(best.s, best.e);
        const ids = cluster.map(c => str(c.r.transaction_id)).filter(Boolean);
        const spanMin = Math.round((cluster[cluster.length - 1].ts - cluster[0].ts) / 60000);
        out.push({
          row: { account_id: acct, ...cluster[0].r },
          rowIndex: cluster[0].i,
          severity: best.sum >= strThr * 2 ? 'critical' : 'high',
          exposure: Math.round(best.sum),
          finding: `Account ${acct}: ${best.cnt} sub-threshold transactions totalling LKR ${Math.round(best.sum).toLocaleString()} within ${spanMin} min — structuring beneath the LKR ${strThr.toLocaleString()} STR threshold.`,
          recommended_action: 'File STR with CBSL FIU within the statutory window; freeze pending review; reconstruct counterparties.',
          triggeredBy: [
            { field: 'cluster_count', value: best.cnt, op: '>=', threshold: minCount, rule: 'Transactions in the window' },
            { field: 'cluster_sum_lkr', value: Math.round(best.sum), op: '>=', threshold: strThr, rule: 'Aggregate ≥ STR threshold while each transaction is below it' },
            { field: 'window_min', value: spanMin, op: '<=', threshold: windowMin, rule: 'Within the structuring time window' },
          ],
          extra: { transaction_ids: ids, structuring_window_min: spanMin },
        });
      }

      // Per-account counterparty concentration + velocity-vs-population-baseline.
      const concPct = (t.concentration_pct ?? 70) / 100;
      const velMult = t.velocity_multiplier ?? 3.0;
      const acctVol = {};
      for (const [acct, items] of Object.entries(byAcct)) acctVol[acct] = items.reduce((s, x) => s + (num(x.r.amount_lkr) ?? 0), 0);
      const vols = Object.values(acctVol).filter(v => v > 0).sort((a, b) => a - b);
      const medianVol = vols.length ? vols[Math.floor(vols.length / 2)] : 0;
      for (const [acct, items] of Object.entries(byAcct)) {
        const total = acctVol[acct]; if (total <= 0) continue;
        const tb = []; let sev = 'medium';
        // counterparty concentration (outflow share to the single biggest counterparty).
        // Needs ≥3 transactions to ≥2 counterparties — a single-payee account isn't
        // "concentrated", it's just low-activity; that would flood the queue.
        const byCp = {};
        for (const x of items) { const cp = str(x.r.counterparty_account); if (cp) byCp[cp] = (byCp[cp] || 0) + (num(x.r.amount_lkr) ?? 0); }
        const topCp = Object.values(byCp).sort((a, b) => b - a)[0] || 0;
        const cpShare = topCp / total;
        if (items.length >= 3 && Object.keys(byCp).length >= 2 && cpShare >= concPct) { tb.push({ field: 'counterparty_concentration_pct', value: Math.round(cpShare * 100), op: '>=', threshold: Math.round(concPct * 100), rule: 'Outflow concentrated to a single counterparty (layering signal)' }); sev = worse(sev, 'high'); }
        // velocity: the registry velocity_multiplier × population median is the
        // hard FLOOR; a robust-z outlier vs the population of account volumes adds
        // statistically-extreme accounts the fixed multiple would miss (min effect
        // = half the floor multiple, so it's still materially above median).
        let velStat = null;
        const floorVel = medianVol > 0 && total >= medianVol * velMult;
        if (floorVel) { tb.push({ field: 'volume_vs_median_x', value: Math.round((total / medianVol) * 10) / 10, op: '>=', threshold: velMult, rule: 'Account volume far above the population median (velocity)' }); sev = worse(sev, 'high'); }
        const roVel = robustOutlier(total, vols, { upper: true, minN: 30, field: 'account_volume_lkr', label: 'Account total volume is a robust-z outlier vs the population (velocity)' });
        if (roVel && medianVol > 0 && total >= medianVol * (velMult * 0.5)) {
          if (!floorVel) tb.push(roVel.tb);
          velStat = roVel.statistic;
          sev = worse(sev, Math.abs(roVel.z) >= DEFAULT_OUTLIER_Z * 1.7 ? 'critical' : 'high');
        }
        if (tb.length === 0) continue;
        out.push({
          row: { account_id: acct, ...items[0].r },
          rowIndex: items[0].i,
          severity: sev,
          statistic: velStat || undefined,
          exposure: Math.round(total),
          finding: `Account ${acct}: ${tb.map(x => x.rule).join('; ')}.`,
          recommended_action: 'Review counterparties and transaction velocity; assess for layering / unusual activity.',
          triggeredBy: tb,
        });
      }

      // Population-level Benford's-Law first-digit test on transaction amounts.
      // A genuine large transaction stream follows Benford; a material deviation
      // over the configured p-value's χ² critical (df=8) signals fabricated or
      // manipulated amounts. Reproducible — pure function of the amount column.
      // EXACT χ² p-value (df=8) via the shared Benford test, which also returns
      // the per-digit observed-vs-expected distribution for charting. Flag when
      // p < the configured significance level α; the p-value flows to confidence
      // (1−p) and the FDR post-pass.
      const amounts = rows.map(r => num(r.amount_lkr)).filter(a => a != null && a > 0);
      const bf = benfordTest(amounts, 1);
      if (bf) {
        const alpha = t.benford_pvalue ?? 0.05;
        if (bf.p < alpha) {
          out.push({
            row: { account_id: 'POPULATION' },
            rowIndex: -1,
            severity: bf.p < alpha / 10 ? 'critical' : 'high',
            finding: `Benford's-Law deviation across ${bf.n.toLocaleString()} transaction amounts (χ²=${bf.chi2}, df=8, p=${bf.p.toExponential(2)} < α=${alpha}) — the first-digit distribution is inconsistent with a natural transaction stream; indicates possible fabricated or manipulated amounts.`,
            recommended_action: 'Investigate amount-entry controls and the highest-deviation digit cohorts; sample transactions for authenticity.',
            triggeredBy: [{ field: 'benford_p', value: Math.round(bf.p * 1e6) / 1e6, op: '<', threshold: alpha, rule: `Benford's-Law first-digit χ²=${bf.chi2} (df=8); p-value below the significance level α` }],
            statistic: { test: 'benford-first-digit', value: bf.chi2, df: 8, p: bf.p },
            extra: { benford_chi_square: bf.chi2, benford_p: bf.p, population_size: bf.n, benford_dist: bf.dist, benford_digits: 1 },
          });
        }
      }

      // Counterparty NETWORK analytics — build the account↔counterparty directed
      // graph and surface structures fixed per-account rules can't see:
      //   • collection HUBS — a counterparty receiving from an unusually large
      //     number of distinct accounts (in-degree robust-z outlier) → mule/funnel.
      //   • distribution FANS — an account paying an unusually large number of
      //     distinct counterparties (out-degree robust-z outlier) → layering.
      //   • round-trips — A→B and B→A both present (2-cycles) → wash/round-tripping.
      const outDeg = {}, inDeg = {};
      for (const r of rows) {
        const a = str(r.account_id), b = str(r.counterparty_account);
        if (!a || !b || a === b) continue;
        (outDeg[a] ||= new Set()).add(b);
        (inDeg[b] ||= new Set()).add(a);
      }
      const inCounts = Object.values(inDeg).map(s => s.size);
      const outCounts = Object.values(outDeg).map(s => s.size);
      for (const [cp, srcs] of Object.entries(inDeg)) {
        const ro = robustOutlier(srcs.size, inCounts, { minN: 20, upper: true, field: 'counterparty_in_degree', label: `Counterparty receives from ${srcs.size} distinct accounts — in-degree robust-z outlier (collection-hub / funnel signal)` });
        if (!ro) continue;
        out.push({ row: { account_id: `CP-HUB:${cp}`, counterparty_account: cp }, rowIndex: -1, severity: Math.abs(ro.z) >= DEFAULT_OUTLIER_Z * 1.7 ? 'critical' : 'high',
          finding: `Counterparty ${cp} receives funds from ${srcs.size} distinct accounts (robust-z ${ro.z.toFixed(1)} vs the network) — collection-hub / funnel-account pattern.`,
          recommended_action: 'Map the contributing accounts; assess for a money-mule funnel; consider an STR on the network.',
          triggeredBy: [ro.tb], statistic: ro.statistic });
      }
      for (const [acct, dsts] of Object.entries(outDeg)) {
        const ro = robustOutlier(dsts.size, outCounts, { minN: 20, upper: true, field: 'account_out_degree', label: `Account pays ${dsts.size} distinct counterparties — out-degree robust-z outlier (distribution/layering signal)` });
        if (!ro) continue;
        out.push({ row: { account_id: `FAN-OUT:${acct}`, account_id_ref: acct }, rowIndex: -1, severity: Math.abs(ro.z) >= DEFAULT_OUTLIER_Z * 1.7 ? 'critical' : 'high',
          finding: `Account ${acct} disburses to ${dsts.size} distinct counterparties (robust-z ${ro.z.toFixed(1)} vs the network) — distribution / layering pattern.`,
          recommended_action: 'Review the destination counterparties and purpose; assess for layering of illicit proceeds.',
          triggeredBy: [ro.tb], statistic: ro.statistic });
      }
      // 2-cycles (round-trips): A->B and B->A both present. Iterate adjacency Sets
      // directly (no string edge keys); report each unordered pair once.
      const seenPair = new Set();
      for (const [a, dsts] of Object.entries(outDeg)) {
        for (const b of dsts) {
          if (outDeg[b] && outDeg[b].has(a)) {
            const key = a < b ? a + "~" + b : b + "~" + a;
            if (seenPair.has(key)) continue; seenPair.add(key);
            out.push({ row: { account_id: "ROUNDTRIP:" + key }, rowIndex: -1, severity: "high",
              finding: `Round-trip detected: funds flow ${a}->${b} AND ${b}->${a} - circular flow consistent with wash / round-tripping.`,
              recommended_action: "Reconstruct the transaction pair; confirm economic purpose; assess for wash transactions.",
              triggeredBy: [{ field: "round_trip_pair", value: 2, op: ">=", threshold: 2, rule: "Reciprocal transfers between the same two accounts (2-cycle)" }] });
          }
        }
      }
      return out;
    },
  },

  // ── INSIDER RISK: per-staff behavioural composite (cross-row) ───────────────
  insider: {
    key: 'staff_id', listKey: 'staff_profiles', summaryKey: 'summary',
    domains: ['people', 'operations'],
    detectAll(rows, t) { return staffComposite(rows, t); },
  },

  // ── STAFF, ACCESS & CONTROL RISK: consolidated cross-layer composite ────────
  // Scores the staff-behaviour layer and, when an Access Rights feed is supplied
  // (ctx.accessRows), correlates it with the entitlement layer — a subject
  // flagged at BOTH layers escalates to critical (cross-layer convergence). With
  // no access feed it degrades gracefully to the behaviour layer only.
  staffAccess: {
    key: 'staff_id', listKey: 'cross_layer_subjects', summaryKey: 'consolidated_summary',
    domains: ['operations', 'people', 'technology'],
    detectAll(rows, t, ctx) {
      let accessByStaff = null;
      if (ctx && Array.isArray(ctx.accessRows)) {
        accessByStaff = {};
        for (const a of ctx.accessRows) { const id = str(a.user_id) || str(a.staff_id); if (id) accessByStaff[id] = a; }
      }
      return staffComposite(rows, t, accessByStaff, { critCut: t.composite_critical, multiLayerBoost: t.multi_layer_boost });
    },
  },

  // ── REGULATORY REPORTING INTEGRITY ──────────────────────────────────────────
  // Two deterministic checks per submitted return line:
  //   (a) FLOOR breach  — submitted value below the CBSL regulatory minimum
  //       (a reportable event on its own).
  //   (b) VARIANCE       — submitted value differs from the value Sentinel
  //       INDEPENDENTLY computes (ctx.computedReturns, from the capital/credit
  //       agents) by more than the configured materiality tolerance. This is the
  //       core "is the return defensible?" reconciliation (Banking Act §46A).
  regReporting: {
    key: 'line_item', listKey: 'variances', summaryKey: 'reporting_summary',
    domains: ['compliance', 'finance'],
    label: r => `${str(r.return_name) || ''} ${str(r.line_item) || ''}`.trim(),
    detect(r, t, ctx) {
      const li = str(r.line_item).toLowerCase();
      const val = num(r.submitted_value);
      if (val == null) return null;
      const unit = str(r.unit).toLowerCase().includes('pct') || str(r.unit) === '%' ? '%' : '';
      // metric → { floor, ref key in computedReturns, tolerance (in pct points) }
      const bps = (n) => (n ?? 0) / 100; // basis points → percentage points
      const specs = [
        { m: /tier\s*1/, floor: 8.5, ref: 'tier1', tol: bps(t.car_tolerance_bps ?? 10), label: 'Tier 1 ratio' },
        { m: /total\s*car|capital\s*adequacy|\bcar\b/, floor: 12.5, ref: 'car', tol: bps(t.car_tolerance_bps ?? 10), label: 'Total CAR' },
        { m: /\blcr\b|liquidity\s*coverage/, floor: 100, ref: 'lcr', tol: (t.lcr_tolerance_pct ?? 2), label: 'LCR' },
        { m: /\bnsfr\b|net\s*stable/, floor: 100, ref: 'nsfr', tol: (t.nsfr_tolerance_pct ?? 2), label: 'NSFR' },
        { m: /leverage/, floor: 3.0, ref: 'leverage', tol: bps(t.leverage_tolerance_bps ?? 15), label: 'Leverage ratio' },
        { m: /stage\s*3|npl|non.?performing/, floor: null, ref: 'stage3', tol: bps(t.stage3_tolerance_bps ?? 15), label: 'Stage 3 ratio' },
        { m: /large\s*exposure|large\s*exp/, floor: null, ref: 'large_exposure', tol: (t.large_exp_tolerance_pct ?? 1.0), label: 'Large Exposures' },
      ];
      const hit = specs.find(s => s.m.test(li));
      if (!hit) return null;
      const tb = []; let sev = 'medium';
      // (a) floor breach
      if (hit.floor != null && val < hit.floor) {
        tb.push({ field: 'submitted_value', value: val, op: '<', threshold: hit.floor, rule: `${hit.label} below CBSL regulatory floor` });
        sev = 'critical';
      }
      // (b) variance vs Sentinel-computed reference
      const computed = ctx && ctx.computedReturns ? ctx.computedReturns[hit.ref] : null;
      if (typeof computed === 'number' && Number.isFinite(computed)) {
        const diff = Math.round(Math.abs(val - computed) * 100) / 100;
        if (diff > hit.tol) {
          tb.push({ field: 'submitted_vs_computed', value: diff, op: '>', threshold: Math.round(hit.tol * 100) / 100, rule: `${hit.label}: submitted ${val}${unit} vs Sentinel-computed ${Math.round(computed * 100) / 100}${unit} — variance exceeds materiality tolerance` });
          // Normalised variance severity (0 at tolerance → 1 at 2× tolerance);
          // critical when it reaches the configured severity cutoff.
          const sevScore = Math.min(1, (diff - hit.tol) / hit.tol);
          sev = worse(sev, sevScore >= (t.severity_critical ?? 0.80) ? 'critical' : 'high');
        }
      }
      if (tb.length === 0) return null;
      const isBreach = hit.floor != null && val < hit.floor;
      return {
        severity: sev,
        finding: `${str(r.return_name) ? str(r.return_name) + ' — ' : ''}${hit.label} for ${str(r.reporting_period)}: ${isBreach ? `submitted ${val}${unit} is BELOW the CBSL floor of ${hit.floor}` : ''}${isBreach && tb.length > 1 ? '; ' : ''}${tb.find(x => x.field === 'submitted_vs_computed') ? `submitted ${val}${unit} ≠ Sentinel-computed ${Math.round((computed) * 100) / 100}${unit} (material variance)` : ''}.`,
        recommended_action: 'Reconcile the submitted return to source; if the submission is wrong, correct and resubmit; if a floor breach is confirmed, notify CBSL with a remediation plan.',
        triggeredBy: tb,
      };
    },
  },
};

// Agents recognised by the engine. Cross-row agents (transaction structuring,
// insider/staffAccess per-staff composites) use detectAll; the rest detect per
// row. Any agent NOT listed here produces an honest empty result (supported:
// false) rather than invented findings. Remaining enhancements: regReporting
// variance-vs-Sentinel-computed reconciliation, and full 3-layer staffAccess.
export const DETECTOR_AGENTS = Object.keys(D);

