// describeDetector(agentId) → engine-derived description with LIVE threshold
// values from the registry. Null for non-engine agents (orchestrator etc.).
export function describeDetector(agentId) {
  const spec = D[agentId], meta = DETECTOR_META[agentId];
  if (!spec || !meta) return null;
  const defs = getDefaults()[agentId] || {};
  return {
    agentId,
    method: meta.method,
    methodLabel: METHOD_LABELS[meta.method] || meta.method,
    inputs: meta.inputs,
    summary: meta.summary,
    rules: meta.rules.map(r => ({ when: r.when, thresholds: (r.thresholds || []).map(k => ({ key: k, value: defs[k] })) })),
    crossAgent: meta.crossAgent || null,
    narrate: meta.narrate !== false,
    properties: { reproducible: true, grounded: true, fullPopulation: true },
    engineVersion: ENGINE_VERSION,
  };
}

const METHOD_LABELS = {
  'deterministic-rule': 'Deterministic rule engine',
  'cross-row-aggregation': 'Cross-row aggregation',
  'statistical-test': 'Statistical test',
  'cross-agent-reconciliation': 'Cross-agent reconciliation',
};

// describeArchitecture() → the compute-first→AI-narrate pipeline + LIVE coverage
// numbers, so the architecture explanation can never claim a stale count.
export function describeArchitecture() {
  const ids = DETECTOR_AGENTS;
  const methodBreakdown = {};
  for (const id of ids) { const m = DETECTOR_META[id]?.method || 'deterministic-rule'; methodBreakdown[METHOD_LABELS[m] || m] = (methodBreakdown[METHOD_LABELS[m] || m] || 0) + 1; }
  return {
    detectorCount: ids.length,
    methodBreakdown,
    pipeline: [
      { step: 'Ingest & reconcile', detail: 'Source feed ingested from the data lake (or an offline extract); record count and control totals reconciled to the source system (IPE) with a provenance attestation before anything runs.' },
      { step: 'Deterministic detection', detail: 'A rule engine scores 100% of the population in code against the thresholds you set in Rule Parameters — no sampling, no LLM in the decision.' },
      { step: 'Statistical scoring & FDR control', detail: 'Where a distribution exists, detectors add transparent statistics — robust-z vs peers, Benford digit tests, binomial/Poisson — so confidence is a real p-value; a Benjamini–Hochberg false-discovery-rate control then bounds spurious hits.' },
      { step: 'Evidence grounding', detail: 'Every finding carries its source row, the exact values, and the rule or statistic that fired — an auditor can re-perform it.' },
      { step: 'AI narrative (optional)', detail: 'Claude writes a plain-English explanation on top of the computed findings; it never decides whether a finding exists or its severity.' },
      { step: 'Governance', detail: 'Four-eyes on conclusions, a tamper-evident audit trail, confidence calibrated to measured precision, input-drift (PSI/KS) monitoring, and per-agent precision (Detection Assurance).' },
    ],
    properties: [
      'Reproducible — identical data yields a byte-identical result and a stable content hash',
      'Grounded — findings tie to source rows, not model assertions',
      'Full population — no sampling, no row cap',
      'Single-sourced thresholds — the rules read live from Rule Parameters',
      'Statistically calibrated — confidence is a tail probability (1−p), false-discovery-rate-bounded, and input-drift monitored',
      'Transparent, not black-box — every method is an explainable statistic (robust-z, Benford, χ²), never an opaque model',
    ],
  };
}

// Load-time self-check (prod-safe): every detector must declare its meta, and
// every threshold it names must exist in the registry. Fails fast at import so
// a detector added/changed without updating its description breaks the build.
// Registry thresholds the live engine does NOT consume, with WHY — so the UI can
// label them honestly and the coverage guardrail below stays green. Anything not
// here and not engine-used trips the guardrail (no silent illusory knob).
//   notification = a policy threshold (not a detection trigger)
//   sla          = an action SLA (belongs to escalation policy)
//   informational= the input is pre-aggregated; the knob can't change the window
//   needs-input  = computable only once the feed carries an extra column
//   meta         = a meta-agent (feedback loop) parameter, not a detector
//   retired      = an LLM-era knob the deterministic engine replaced
export const NON_ENGINE_THRESHOLDS = {
  'credit.isoforest_critical': 'retired', 'credit.isoforest_flag': 'retired', 'credit.car_impact_bps': 'notification',
  'transaction.structuring_score': 'retired',
  'digital.travel_impossible_ratio': 'retired',
  'mje.tax_variance_pct': 'retired',
  'insider.cross_cluster_min': 'retired',
  'capital.leverage_min': 'needs-input',
  'creditFraud.siphon_window_hours': 'informational',
  'regReporting.str_reconciliation_lag': 'retired',
  'staffAccess.evidence_preservation_sla': 'sla',
  'feedbackLoop.min_false_positives': 'meta', 'feedbackLoop.min_confidence': 'meta', 'feedbackLoop.max_recommendations_per_run': 'meta',
};

// 'engine' (drives live detection) | a NON_ENGINE_THRESHOLDS tag | 'unmapped'.
export function thresholdEngineStatus(agentId, key) {
  const meta = DETECTOR_META[agentId];
  if (meta && meta.rules.some(r => (r.thresholds || []).includes(key))) return 'engine';
  return NON_ENGINE_THRESHOLDS[`${agentId}.${key}`] || 'unmapped';
}

(function validateDetectorMeta() {
  const defsAll = getDefaults();
  for (const id of Object.keys(D)) {
    const meta = DETECTOR_META[id];
    if (!meta) throw new Error(`detectionEngine: detector "${id}" has no DETECTOR_META entry — document how it detects.`);
    if (!meta.method || !meta.summary || !Array.isArray(meta.inputs) || !Array.isArray(meta.rules)) {
      throw new Error(`detectionEngine: DETECTOR_META["${id}"] is missing required fields (method/summary/inputs/rules).`);
    }
    const defs = defsAll[id] || {};
    for (const r of meta.rules) for (const k of (r.thresholds || [])) {
      if (!(k in defs)) throw new Error(`detectionEngine: DETECTOR_META["${id}"] names threshold "${k}" that is not in the registry for "${id}".`);
    }
  }
  // COVERAGE GUARDRAIL: every registry threshold must be engine-used or tagged.
  // A new knob that is neither wired nor tagged fails the build — no illusory config.
  for (const [agentId, block] of Object.entries(defsAll)) {
    for (const key of Object.keys(block)) {
      if (thresholdEngineStatus(agentId, key) === 'unmapped') {
        throw new Error(`detectionEngine: threshold "${agentId}.${key}" is neither used by the engine nor tagged in NON_ENGINE_THRESHOLDS — wire it into a detector or tag why it isn't.`);
      }
    }
  }
})();

// ─── ENGINE ENTRYPOINT ───────────────────────────────────────────────────────
// detectFindings(agentId, rows, thresholds, ctx) → grounded result block.
// Pure & deterministic: identical (agentId, rows, thresholds, ctx.asOfMs) yields
// byte-identical output and a stable `_engine.contentHash`.
export function detectFindings(agentId, rows, thresholds = null, ctx = {}) {
  const spec = D[agentId];
  const t = (thresholds && thresholds[agentId]) || thresholds || (getDefaults()[agentId] || {});
  const asOfMs = ctx.asOfMs ?? null;
  const safeRows = Array.isArray(rows) ? rows : [];

  if (!spec) {
    return {
      key_findings: [],
      _engine: { version: ENGINE_VERSION, agentId, rowsAnalysed: safeRows.length, flagged: 0, deterministic: true, supported: false, contentHash: stableHash([agentId, safeRows.length]) },
    };
  }

  const findings = [];
  let flaggedExposure = 0;
  const sevCounts = { critical: 0, high: 0, medium: 0, low: 0 };

  // Collect raw results. Most agents detect PER ROW; cross-row agents (e.g.
  // transaction structuring, per-staff insider composites) implement detectAll,
  // which receives the whole population and returns results carrying their own
  // representative row + rowIndex.
  // detectors receive the full ctx (asOfMs + any cross-data the caller supplies,
  // e.g. ctx.computedReturns for regReporting, ctx.accessRows for staffAccess).
  const detCtx = { ...ctx, asOfMs };
  // Peer distributions for per-row detectors that opt in via spec.peerStats — so
  // a per-row detect() can judge a value against the whole population (robust-z)
  // without re-deriving it per row. { [field]: { median, mad, n } }.
  if (Array.isArray(spec.peerStats) && spec.peerStats.length) {
    detCtx.peerStats = {};
    for (const f of spec.peerStats) {
      const vals = safeRows.map(r => num(r[f])).filter(v => v != null);
      if (vals.length) detCtx.peerStats[f] = { median: median(vals), mad: mad(vals), n: vals.length };
    }
  }
  const raw = [];
  if (typeof spec.detectAll === 'function') {
    let arr; try { arr = spec.detectAll(safeRows, t, detCtx) || []; } catch { arr = []; }
    for (const res of arr) {
      if (!res) continue;
      raw.push({ row: res.row || {}, rowIndex: res.rowIndex ?? -1, res });
    }
  } else {
    for (let i = 0; i < safeRows.length; i++) {
      const row = safeRows[i];
      if (!row || typeof row !== 'object') continue;
      let res; try { res = spec.detect(row, t, detCtx); } catch { res = null; }
      if (res) raw.push({ row, rowIndex: i, res });
    }
  }
  // Optional cross-row/population pass ON TOP of per-row detect (e.g. per-sector
  // NPL rate, per-branch composite, per-introducer concentration). Each result
  // carries its own representative row + rowIndex.
  if (typeof spec.aggregate === 'function') {
    let extra; try { extra = spec.aggregate(safeRows, t, detCtx) || []; } catch { extra = []; }
    for (const res of extra) { if (res) raw.push({ row: res.row || {}, rowIndex: res.rowIndex ?? -1, res }); }
  }

  for (const { row, rowIndex: i, res } of raw) {
    const exposure = res.exposure != null ? res.exposure
      : (spec.exposureField != null ? (num(row[spec.exposureField]) ?? 0) : 0);
    flaggedExposure += exposure;
    const conf = statisticalConfidence(res);
    const finding = {
      ...row,                                   // carry raw signals for downstream consumers
      ...(res.extra || {}),
      finding: res.finding,
      severity: res.severity,
      affected_exposure_lkr: exposure,
      recommended_action: res.recommended_action || '',
      domain_tags: spec.domains || ['audit'],
      confidence: conf.value,
      confidenceBasis: conf.basis,             // 'p-value' (real significance) | 'margin'
      evidence: {
        sourceRef: { key: spec.key ? row[spec.key] : null, field: spec.key || null, rowIndex: i },
        triggeredBy: res.triggeredBy,
        ruleId: agentId,
        recomputedExposureLkr: exposure,
        statistic: res.statistic || null,      // { test, value, df?, p, peerMedian?, mad? } when distributional
      },
      detection: { method: res.statistic ? 'statistical-test' : 'deterministic-rule', engineVersion: ENGINE_VERSION, computedAt: ctx.computedAt || null },
    };
    findings.push(finding);
  }

  // Multiple-testing correction over the agent's statistical findings (S1).
  const fdr = applyFdr(findings, Number.isFinite(ctx.fdrQ) ? ctx.fdrQ : DEFAULT_FDR_Q);

  // Severity counts AFTER FDR demotion so headline counts reflect the corrected set.
  for (const f of findings) sevCounts[f.severity] = (sevCounts[f.severity] || 0) + 1;

  const summary = {
    total_analyzed: safeRows.length,
    flagged_count: findings.length,
    flagged_exposure_lkr: Math.round(flaggedExposure),
    critical_count: sevCounts.critical,
    by_severity: sevCounts,
    fdr: fdr.tested ? fdr : undefined,
  };

  const block = {
    [spec.summaryKey]: summary,
    [spec.listKey]: findings,
    key_findings: findings,                     // canonical list the UI/aggregations consume
    _engine: {
      version: ENGINE_VERSION, agentId, rowsAnalysed: safeRows.length,
      flagged: findings.length, deterministic: true, supported: true,
      fdr: fdr.tested ? fdr : null,             // multiple-testing summary (S1)
      contentHash: stableHash([agentId, safeRows.length, findings.map(f => ({ k: f.evidence.sourceRef.key, s: f.severity, t: f.evidence.triggeredBy }))]),
    },
  };
  return block;
}

// Run several agents at once. `datasets` = { [agentId]: rows[] }.
export function detectAll(datasets, thresholds = null, ctx = {}) {
  const out = {};
  for (const [agentId, rows] of Object.entries(datasets || {})) {
    out[agentId] = detectFindings(agentId, rows, thresholds, ctx);
  }
  return out;
}

// ─── CROSS-AGENT REFERENCE METRICS ───────────────────────────────────────────
// Independently re-computes the headline regulatory ratios from RAW uploaded
// rows so regReporting can reconcile a SUBMITTED return against what Sentinel
// derives. Pass the result as ctx.computedReturns when running regReporting.
// `datasets` = { capital: rows[], credit: rows[] } (raw parsed CSV rows).
export function computeReturnReferences(datasets = {}) {
  const refs = {};
  const capRows = Array.isArray(datasets.capital) ? datasets.capital : [];
  if (capRows.length) {
    // Latest quarter = last row (feeds are chronological); fall back to last present.
    const r = capRows[capRows.length - 1];
    const tier1 = num(r.tier1_capital_lkr_bn), tier2 = num(r.tier2_capital_lkr_bn);
    const rwa = (num(r.rwa_credit_lkr_bn) ?? 0) + (num(r.rwa_market_lkr_bn) ?? 0) + (num(r.rwa_operational_lkr_bn) ?? 0);
    const hqla = (num(r.hqla_level1_lkr_bn) ?? 0) + 0.85 * (num(r.hqla_level2a_lkr_bn) ?? 0) + 0.5 * (num(r.hqla_level2b_lkr_bn) ?? 0);
    const nco = num(r.net_cash_outflow_30d_lkr_bn), asf = num(r.available_stable_funding_lkr_bn), rsf = num(r.required_stable_funding_lkr_bn);
    if (rwa) {
      if (tier1 != null) refs.tier1 = (tier1 / rwa) * 100;
      if (tier1 != null && tier2 != null) refs.car = ((tier1 + tier2) / rwa) * 100;
    }
    if (nco) refs.lcr = (hqla / nco) * 100;
    if (rsf) refs.nsfr = (asf / rsf) * 100;
    // Basel III leverage ratio = Tier 1 ÷ total exposure measure (on- + off-balance).
    const expMeasure = num(r.total_exposure_measure_lkr_bn);
    if (tier1 != null && expMeasure) refs.leverage = (tier1 / expMeasure) * 100;
  }
  const credRows = Array.isArray(datasets.credit) ? datasets.credit : [];
  if (credRows.length) {
    // Stage 3 ratio = Stage-3 exposure ÷ total exposure (%).
    let total = 0, s3 = 0;
    for (const r of credRows) { const e = num(r.exposure_lkr) ?? 0; total += e; if (num(r.assigned_stage) === 3) s3 += e; }
    if (total > 0) refs.stage3 = (s3 / total) * 100;
  }
  const cpRows = Array.isArray(datasets.connectedParty) ? datasets.connectedParty : [];
  if (cpRows.length) {
    // Large Exposures reference = the largest single-obligor exposure (% of capital).
    let maxPct = 0;
    for (const r of cpRows) { const p = num(r.single_obligor_pct) ?? 0; if (p > maxPct) maxPct = p; }
    if (maxPct > 0) refs.large_exposure = maxPct;
  }
  return refs;
}

// Engine-computed prudential SUMMARY metrics, published onto an agent's result so
// the Bank Position (Regulatory Capital) and Compliance Scoring pages read LIVE
// engine output rather than the legacy LLM-agent schema those fields came from.
// Purely additive + deterministic — derived only from the agent's own rows and the
// findings already on the result. Fields left null are genuinely data-limited
// (e.g. the leverage exposure measure isn't in the feed) — never fabricated.
export function enrichAgentResult(agentId, rows, result) {
  const safe = Array.isArray(rows) ? rows : [];
  if (!safe.length || !result || typeof result !== 'object') return result;
  // Published metrics are rounded to 2dp so consumers that render the raw value
  // (e.g. the Compliance "regulatory floors" table) don't show 16.130434…% — the
  // engine math keeps full precision; only the display-facing summary is rounded.
  const r2 = (v) => (v == null || !Number.isFinite(v) ? null : Math.round(v * 100) / 100);

  if (agentId === 'capital') {
    const refs = computeReturnReferences({ capital: safe });
    result.capital_position = {
      ...(result.capital_position || {}),
      car_tier1_pct: r2(refs.tier1),
      car_total_pct: r2(refs.car),
      // Basel III leverage = Tier 1 ÷ total exposure measure (computed when the
      // feed carries total_exposure_measure_lkr_bn; null otherwise — never faked).
      leverage_ratio_pct: r2(refs.leverage),
    };
    result.liquidity_position = {
      ...(result.liquidity_position || {}),
      lcr_pct: r2(refs.lcr),
      nsfr_pct: r2(refs.nsfr),
    };
  } else if (agentId === 'credit') {
    const refs = computeReturnReferences({ credit: safe });
    // Sector concentration = total book exposure per sector (capital-consumption distribution).
    const bySector = {};
    for (const r of safe) {
      const s = str(r.sector) || 'Unclassified';
      bySector[s] = (bySector[s] || 0) + (num(r.exposure_lkr) ?? 0);
    }
    result.sector_concentration = Object.entries(bySector)
      .map(([sector, exp]) => ({ sector, flagged_exposure_lkr: Math.round(exp) }))
      .sort((a, b) => b.flagged_exposure_lkr - a.flagged_exposure_lkr);
    result.capital_impact = { ...(result.capital_impact || {}), current_stage3_ratio: r2(refs.stage3) };
  } else if (agentId === 'kyc') {
    // Bank-wide KYC gap rate = share of customers the engine flagged with a gap.
    const s = result.compliance_summary;
    if (s && s.total_analyzed > 0) s.kyc_gap_pct = r2((s.flagged_count / s.total_analyzed) * 100);
  } else if (agentId === 'suspense') {
    // deriveMeasurements gates on aging_distribution before reading the worst
    // flagged_accounts[].aging_days (the findings already carry aging_days via the row spread).
    const fa = result.flagged_accounts || [];
    const worst = fa.reduce((m, a) => Math.max(m, num(a.aging_days) ?? 0), 0);
    result.aging_distribution = { worst_days: worst, flagged_count: fa.length };
  } else if (agentId === 'connectedParty') {
    // Consumers read exposure_pct_of_capital; rows carry it as single_obligor_pct.
    for (const b of (result.single_obligor_breaches || [])) {
      if (b.exposure_pct_of_capital == null) b.exposure_pct_of_capital = num(b.single_obligor_pct) ?? null;
    }
    // Connected-group exposure = Σ single-obligor % across a group's members (each
    // % is of the same capital base, so additive). Only genuine multi-member groups
    // qualify as a "connected group". Surfaced as connected_group_breaches.
    const byGroup = {};
    for (const r of safe) {
      const g = str(r.group_id);
      if (!g) continue;
      (byGroup[g] = byGroup[g] || { pct: 0, members: 0 });
      byGroup[g].pct += (num(r.single_obligor_pct) ?? 0);
      byGroup[g].members += 1;
    }
    result.connected_group_breaches = Object.entries(byGroup)
      .filter(([, v]) => v.members >= 2)
      .map(([group_id, v]) => ({ group_id, members: v.members, exposure_pct_of_capital: Math.round(v.pct * 100) / 100 }))
      .sort((a, b) => b.exposure_pct_of_capital - a.exposure_pct_of_capital);
  } else if (agentId === 'alm') {
    // Worst-case IRRBB metrics across buckets/scenarios. EVE sensitivity is fed in
    // basis points; the floor is expressed as % of Tier 1, so bps → % (÷100).
    let eveBps = 0, gapPct = 0;
    for (const r of safe) {
      eveBps = Math.max(eveBps, Math.abs(num(r.eve_sensitivity_bps) ?? 0));
      gapPct = Math.max(gapPct, Math.abs(num(r.cumulative_gap_pct) ?? 0));
    }
    result.alm_summary = {
      ...(result.alm_summary || {}),
      eve_sensitivity_pct: r2(eveBps / 100),
      cumulative_gap_pct: r2(gapPct),
    };
  }
  return result;
}
